import React, { useState, useRef, useEffect } from 'react';
import { X, Send, Bot, User, Sparkles, Loader2, CheckCircle2, MessageSquarePlus, Info, Zap, Settings, Shield, ChevronRight, Maximize2, ArrowLeft, Undo2, Pencil, Save, RotateCcw } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

interface OperationalContextBuilderProps {
  isOpen: boolean;
  onClose: () => void;
  onComplete: (context: string) => void;
  onUndo: () => void;
  canUndo: boolean;
}

interface Message {
  role: 'user' | 'assistant';
  content: string;
  isDraft?: boolean;
}

export const OperationalContextBuilder: React.FC<OperationalContextBuilderProps> = ({ isOpen, onClose, onComplete, onUndo, canUndo }) => {
  const [messages, setMessages] = useState<Message[]>([
    { 
      role: 'assistant', 
      content: "Welcome to the **Asset Intelligence Workstation**. \n\nI am your lead RCM facilitator. To build a world-class maintenance strategy, we first need a deep understanding of your asset's operational reality. \n\nPlease tell me: **What asset are we analyzing today?** (e.g., 'A high-pressure feed pump for a steam turbine system' or 'An overhead gantry crane in a steel mill')." 
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [latestDraft, setLatestDraft] = useState<string | null>(null);
  const [showFullReview, setShowFullReview] = useState(false);
  const [isEditingDraft, setIsEditingDraft] = useState(false);
  const [editableText, setEditableText] = useState('');

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current && !showFullReview) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading, showFullReview]);

  if (!isOpen) return null;

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMessage }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const history = messages.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.content}`).join('\n');

      const prompt = `
        CONVERSATION HISTORY:
        ${history}

        NEW USER REQUEST: ${userMessage}

        TASK:
        Generate a comprehensive and highly detailed "Operational Context" draft according to SAE JA1011 standards. 

        REQUIRED DEPTH:
        1. System Boundaries: List main components (e.g. housing, impeller, shaft, seals, motor, bearings).
        2. Functional Requirements: Primary performance (e.g. flow/pressure) and secondary (containment, safety).
        3. Operating Conditions: Temperature, humidity, corrosive environment, and duty cycle.
        4. Failure Mechanisms: Typical wear modes (erosion, fatigue, cavitation).
        5. Maintenance Intent: Proactive vs. Reactive goals.

        FORMATTING RULES:
        - DO NOT USE # OR ## OR * SYMBOLS FOR HEADERS.
        - Use plain text but clearly separated sections with titles in CAPITAL LETTERS.
        - Use bullet points for lists but don't use symbols that look like code.
        - Wrap the FINAL full structured draft in <DRAFT> tags.
        - Provide a professional engineer-to-engineer summary before the tags.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are a world-class RCM Analyst. Your style is professional, technical, and concise. You provide extremely detailed context that includes component breakdowns, functions, and likely failure modes."
        }
      });

      const aiText = response.text || "Communication error with the RCM engine. Please try again.";

      const draftMatch = aiText.match(/<DRAFT>([\s\S]*?)<\/DRAFT>/);
      let draftContent = null;
      let cleanResponse = aiText.replace(/<DRAFT>[\s\S]*?<\/DRAFT>/, '').trim();

      if (draftMatch) {
        draftContent = draftMatch[1].trim();
        setLatestDraft(draftContent);
        setEditableText(draftContent);
      }

      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: cleanResponse,
        isDraft: !!draftContent 
      }]);

    } catch (error) {
      setMessages(prev => [...prev, { role: 'assistant', content: "An error occurred during technical synthesis. Please check your network." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleApply = () => {
    if (latestDraft) {
      onComplete(latestDraft);
      onClose();
    }
  };

  const handleStartEditing = () => {
    setEditableText(latestDraft || '');
    setIsEditingDraft(true);
  };

  const handleSaveEdit = () => {
    setLatestDraft(editableText);
    setIsEditingDraft(false);
  };

  const renderFormattedDraft = (content: string) => {
    return content.split('\n').map((line, i) => {
      const trimmed = line.trim();
      const cleanLine = trimmed.replace(/\*\*/g, '');

      const isHeader = /^[A-Z\s]{5,40}$/.test(cleanLine) || 
                       cleanLine.startsWith('SECTION') || 
                       cleanLine.includes('IDENTIFICATION') ||
                       cleanLine.includes('ENVIRONMENT') ||
                       cleanLine.includes('FAILURE') ||
                       cleanLine.includes('STRATEGY') ||
                       cleanLine.includes('CONTEXT');

      if (isHeader && cleanLine.length > 3) {
        return (
          <div key={i} className="mt-10 mb-6 border-b-2 border-slate-100 pb-3">
            <h4 className="text-[13px] font-black text-indigo-600 uppercase tracking-[0.3em]">{cleanLine}</h4>
          </div>
        );
      }

      if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
        return (
          <div key={i} className="flex gap-4 ml-4 my-4">
            <ChevronRight size={18} className="text-indigo-400 mt-1 shrink-0" />
            <span className="text-[16px] text-slate-700 font-medium leading-relaxed">{trimmed.replace(/^[*|-]\s*|^\d+\.\s*/, '')}</span>
          </div>
        );
      }

      if (!trimmed) return <div key={i} className="h-6"></div>;

      return <p key={i} className="text-[16px] text-slate-700 leading-relaxed mb-4 font-medium">{cleanLine}</p>;
    });
  };

  const renderFormattedMessage = (content: string) => {
    return content.split('\n').map((line, i) => {
      const trimmed = line.trim();
      const cleanLine = trimmed.replace(/\*\*/g, '');

      const isHeader = /^[A-Z\s]{5,25}$/.test(cleanLine) || 
                       cleanLine.startsWith('SECTION') || 
                       cleanLine.includes('IDENTIFICATION');

      if (isHeader && cleanLine.length > 3) {
        return (
          <div key={i} className="mt-6 mb-3 border-b border-slate-100 pb-2">
            <h4 className="text-[11px] font-black text-indigo-600 uppercase tracking-[0.2em]">{cleanLine}</h4>
          </div>
        );
      }

      if (trimmed.startsWith('- ') || trimmed.startsWith('* ') || trimmed.match(/^\d+\./)) {
        return (
          <div key={i} className="flex gap-3 ml-2 my-2">
            <ChevronRight size={14} className="text-indigo-400 mt-1 shrink-0" />
            <span className="text-[14px] text-slate-700 font-medium leading-relaxed">{trimmed.replace(/^[*|-]\s*|^\d+\.\s*/, '')}</span>
          </div>
        );
      }

      if (!trimmed) return <div key={i} className="h-4"></div>;

      return <p key={i} className="text-[14px] text-slate-700 leading-relaxed mb-3 font-medium">{cleanLine}</p>;
    });
  };

  return (
    <div className="fixed inset-0 z-[70] flex items-center justify-center bg-slate-900/40 backdrop-blur-xl p-4 sm:p-8 animate-in fade-in duration-500">
      <div className="bg-white rounded-[2.5rem] shadow-[0_32px_128px_-16px_rgba(0,0,0,0.15)] w-full max-w-6xl h-full max-h-[92vh] overflow-hidden flex flex-col animate-in zoom-in-95 duration-500 border border-white/40">

        {/* Workstation Header */}
        <div className="bg-white px-10 py-7 flex justify-between items-center shrink-0 border-b border-slate-50">
          <div className="flex items-center gap-6">
            <div className="p-4 bg-indigo-600 rounded-[1.5rem] shadow-2xl shadow-indigo-100 ring-4 ring-indigo-50">
              <Sparkles size={24} className="text-white fill-white/20" />
            </div>
            <div>
              <h3 className="font-black text-2xl tracking-tighter text-slate-900 uppercase">
                {showFullReview ? (isEditingDraft ? 'Editor Mode' : 'Document Review') : 'Context Intelligence Hub'}
              </h3>
              <div className="flex items-center gap-3 mt-1.5">
                <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 rounded-md border border-emerald-100">
                  <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                  <span className="text-[9px] text-emerald-700 font-black uppercase tracking-widest">{isEditingDraft ? 'Unsaved Changes' : 'Live Synthesis'}</span>
                </div>
                <span className="text-[9px] text-slate-400 font-black uppercase tracking-widest">Industry standard SAE JA1011</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-3">
            <button
              onClick={onUndo}
              disabled={!canUndo}
              className={`p-3 rounded-full transition-all ${
                canUndo ? 'bg-slate-100 text-slate-600 hover:bg-slate-200' : 'text-slate-200 opacity-20'
              }`}
              title="Undo last action"
            >
              <Undo2 size={28} />
            </button>
            <button onClick={onClose} className="p-3 bg-slate-50 text-slate-400 hover:bg-red-50 hover:text-red-500 rounded-full transition-all duration-300">
              <X size={28} />
            </button>
          </div>
        </div>

        {/* Main Interface Area */}
        <div className="flex-1 flex overflow-hidden bg-white relative">

          {showFullReview ? (
            /* FULL SCREEN REVIEW MODE */
            <div className="flex-1 flex flex-col animate-in slide-in-from-right duration-500">
              <div className="flex-1 overflow-y-auto px-10 py-16 bg-slate-50/30 custom-scrollbar">
                <div className="max-w-4xl mx-auto">
                  <div className="flex justify-between items-center mb-10">
                    <button 
                      onClick={() => { setShowFullReview(false); setIsEditingDraft(false); }}
                      className="flex items-center gap-2 text-indigo-600 font-black text-xs uppercase tracking-widest hover:-translate-x-1 transition-transform"
                    >
                      <ArrowLeft size={16} /> Back to Chat
                    </button>

                    {!isEditingDraft ? (
                      <button 
                        onClick={handleStartEditing}
                        className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-50 hover:text-indigo-600 transition-all shadow-sm"
                      >
                        <Pencil size={14} /> Edit Context
                      </button>
                    ) : (
                      <div className="flex gap-3">
                        <button 
                          onClick={handleSaveEdit}
                          className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all shadow-md"
                        >
                          <Save size={14} /> Save Changes
                        </button>
                        <button 
                          onClick={() => setIsEditingDraft(false)}
                          className="flex items-center gap-2 px-4 py-2 bg-white border border-slate-200 text-slate-400 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all shadow-sm"
                        >
                          <RotateCcw size={14} /> Cancel
                        </button>
                      </div>
                    )}
                  </div>

                  <div className="bg-white p-12 sm:p-20 rounded-[3rem] shadow-2xl border border-slate-100 mb-20">
                    <div className="flex items-center gap-4 mb-12">
                      <div className={`w-1.5 h-16 ${isEditingDraft ? 'bg-amber-500' : 'bg-indigo-600'} rounded-full`}></div>
                      <div>
                        <h2 className="text-4xl font-black text-slate-900 tracking-tighter uppercase mb-2">
                          {isEditingDraft ? 'Context Refinement' : 'Operational Context Report'}
                        </h2>
                        <p className="text-sm font-bold text-slate-400 uppercase tracking-[0.2em]">
                          {isEditingDraft ? 'Manual adjustment of technical parameters' : 'Generated for RCM Strategic Analysis'}
                        </p>
                      </div>
                    </div>

                    {isEditingDraft ? (
                      <textarea
                        value={editableText}
                        onChange={(e) => setEditableText(e.target.value)}
                        className="w-full min-h-[600px] p-10 bg-slate-50 border-2 border-indigo-100 rounded-[2rem] text-slate-700 text-lg font-medium leading-relaxed focus:ring-4 focus:ring-indigo-100 outline-none shadow-inner resize-none"
                        placeholder="Refine your operational context here..."
                      />
                    ) : (
                      <div className="prose prose-slate max-w-none">
                        {latestDraft && renderFormattedDraft(latestDraft)}
                      </div>
                    )}
                  </div>
                </div>
              </div>

              <div className="p-10 bg-white border-t border-slate-50 flex justify-center shadow-[0_-20px_40px_rgba(0,0,0,0.02)]">
                <div className="max-w-4xl w-full flex gap-6">
                  <button
                    onClick={handleApply}
                    disabled={isEditingDraft}
                    className={`flex-1 py-6 rounded-[2rem] text-sm font-black uppercase tracking-[0.25em] transition-all flex items-center justify-center gap-3 shadow-2xl active:scale-95 ${isEditingDraft ? 'bg-slate-100 text-slate-300 cursor-not-allowed' : 'bg-slate-900 text-white hover:bg-indigo-600 shadow-slate-200'}`}
                  >
                    <CheckCircle2 size={24} />
                    Confirm & Transfer to Workspace
                  </button>
                  <button 
                    onClick={() => { setShowFullReview(false); setIsEditingDraft(false); }}
                    className="px-12 py-6 bg-white border-2 border-slate-100 text-slate-400 rounded-[2rem] text-sm font-black uppercase tracking-widest hover:text-slate-600 hover:bg-slate-50 transition-all"
                  >
                    Close Review
                  </button>
                </div>
              </div>
            </div>
          ) : (
            /* CONVERSATIONAL STREAM */
            <div className="flex-1 flex flex-col overflow-hidden animate-in fade-in duration-300">
              <div 
                ref={scrollRef}
                className="flex-1 overflow-y-auto px-6 py-10 space-y-12 custom-scrollbar"
              >
                <div className="max-w-4xl mx-auto space-y-10">
                  {messages.map((m, i) => (
                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
                      <div className={`flex gap-6 max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`w-12 h-12 rounded-[1.2rem] shrink-0 flex items-center justify-center shadow-2xl transition-all duration-500 ${m.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-white'}`}>
                          {m.role === 'user' ? <User size={22} /> : <Bot size={24} />}
                        </div>
                        <div className="flex flex-col gap-4 min-w-0">
                          <div className={`p-8 rounded-[2.2rem] shadow-sm border ${
                            m.role === 'user' 
                              ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none text-lg font-bold shadow-indigo-100' 
                              : 'bg-white text-slate-800 border-slate-100 rounded-tl-none ring-1 ring-slate-50'
                          }`}>
                            {m.role === 'user' ? <p className="leading-relaxed">{m.content}</p> : renderFormattedMessage(m.content)}
                          </div>

                          {m.isDraft && latestDraft && i === messages.length - 1 && (
                            <div className="bg-slate-50/50 rounded-[2.5rem] border border-slate-100 p-8 space-y-6 mt-2 animate-in fade-in zoom-in-95 duration-700">
                               <div className="flex items-center justify-between">
                                 <div className="flex items-center gap-3">
                                   <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><Settings size={18} /></div>
                                   <h5 className="text-xs font-black text-slate-900 uppercase tracking-widest">Technical Context Draft</h5>
                                 </div>
                                 <button 
                                   onClick={() => setShowFullReview(true)}
                                   className="text-[10px] font-black text-indigo-600 hover:text-indigo-700 flex items-center gap-2 uppercase tracking-widest"
                                 >
                                   <Maximize2 size={14} /> Full Screen Review & Edit
                                 </button>
                               </div>

                               <div className="bg-white p-8 rounded-[1.8rem] border border-slate-200 shadow-inner max-h-[250px] overflow-y-auto custom-scrollbar text-slate-700 text-[14px] leading-relaxed font-medium whitespace-pre-wrap">
                                 {latestDraft}
                               </div>

                               <div className="flex gap-4">
                                  <button
                                    onClick={handleApply}
                                    className="flex-1 py-5 bg-slate-900 text-white rounded-2xl text-[12px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 shadow-2xl shadow-slate-200 active:scale-95"
                                  >
                                    <MessageSquarePlus size={20} />
                                    Confirm & Export
                                  </button>
                                  <button
                                    onClick={() => setShowFullReview(true)}
                                    className="px-6 py-5 bg-white border border-slate-200 text-slate-500 rounded-2xl text-[12px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all"
                                  >
                                    Edit Large
                                  </button>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}

                  {isLoading && (
                    <div className="flex justify-start">
                      <div className="flex gap-6 items-center">
                        <div className="w-12 h-12 rounded-[1.2rem] bg-indigo-50 flex items-center justify-center animate-pulse shadow-inner">
                          <Loader2 size={24} className="text-indigo-600 animate-spin" />
                        </div>
                        <div className="px-6 py-4 bg-white border border-slate-100 rounded-full shadow-sm flex items-center gap-3">
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Asset Intelligence Synthesis</span>
                           <div className="flex gap-1.5">
                             <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                             <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                             <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                           </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Input Station */}
              <div className="p-10 shrink-0 border-t border-slate-50 bg-white shadow-[0_-20px_40px_rgba(0,0,0,0.02)]">
                <div className="max-w-4xl mx-auto">
                  <div className="flex gap-6">
                    <div className="flex-1 relative group">
                      <input 
                        type="text" 
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && handleSend()}
                        placeholder="e.g. Help me define the context for a cooling tower fan..."
                        className="w-full bg-slate-50 border-2 border-slate-50 rounded-[2rem] px-8 py-6 text-base font-bold text-slate-800 focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-100 outline-none transition-all placeholder:text-slate-300 shadow-inner pr-24"
                      />
                      <div className="absolute right-6 top-1/2 -translate-y-1/2 flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-100 rounded-lg text-[10px] font-black text-slate-300 pointer-events-none group-focus-within:opacity-0 transition-opacity">
                        <Settings size={12} /> ENTER
                      </div>
                    </div>
                    <button 
                      onClick={handleSend}
                      disabled={!input.trim() || isLoading}
                      className="px-10 bg-slate-900 text-white rounded-[2rem] hover:bg-indigo-600 active:scale-95 disabled:opacity-20 transition-all shadow-2xl flex items-center justify-center gap-3 group"
                    >
                      <span className="font-black text-sm uppercase tracking-widest">Analyze</span>
                      <Send size={20} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                    </button>
                  </div>

                  <div className="mt-6 flex justify-center items-center gap-8 text-[10px] font-black text-slate-300 uppercase tracking-[0.2em]">
                     <div className="flex items-center gap-2"><Shield size={14} className="text-slate-200" /> SAE JA1011 Logic</div>
                     <div className="w-1.5 h-1.5 rounded-full bg-slate-100"></div>
                     <div className="flex items-center gap-2"><Zap size={14} className="text-slate-200" /> ISO 14224 Mapping</div>
                     <div className="w-1.5 h-1.5 rounded-full bg-slate-100"></div>
                     <div className="flex items-center gap-2"><Info size={14} className="text-slate-200" /> Component Breakdown</div>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet } from '../services/geminiService';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, Copy, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, LayoutList
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const COLORS = {
  High: '#ef4444',
  Medium: '#f59e0b',
  Low: '#10b981'
};

const getTaskImage = (task: string): string => {
  const t = (task || '').toLowerCase();
  if (t.includes('thermal') || t.includes('infrared') || t.includes('thermography') || t.includes('heat') || t.includes('temperature')) 
    return 'https://images.unsplash.com/photo-1504917595217-d4dc5ebe6122?auto=format&fit=crop&w=800&q=80';
  if (t.includes('vibration') || t.includes('accelerometer') || t.includes('oscillation') || t.includes('align')) 
    return 'https://images.unsplash.com/photo-1581094288338-2314dddb7ece?auto=format&fit=crop&w=800&q=80';
  if (t.includes('oil') || t.includes('lubricat') || t.includes('grease') || t.includes('sample') || t.includes('fluid')) 
    return 'https://images.unsplash.com/photo-1621905252507-b35492cc74b4?auto=format&fit=crop&w=800&q=80';
  if (t.includes('motor') || t.includes('voltage') || t.includes('current') || t.includes('insulation') || t.includes('winding') || t.includes('electric')) 
    return 'https://images.unsplash.com/photo-1581092918056-0c4c3acd3789?auto=format&fit=crop&w=800&q=80';
  if (t.includes('ultrasonic') || t.includes('sound') || t.includes('acoustic') || t.includes('nds') || t.includes('ndt')) 
    return 'https://images.unsplash.com/photo-1581092335397-9583eb92d232?auto=format&fit=crop&w=800&q=80';
  if (t.includes('visual') || t.includes('check') || t.includes('inspect') || t.includes('look') || t.includes('monitor')) 
    return 'https://images.unsplash.com/photo-1581092160562-40aa08e78837?auto=format&fit=crop&w=800&q=80';
  if (t.includes('clean') || t.includes('wash') || t.includes('sweep') || t.includes('housekeeping')) 
    return 'https://images.unsplash.com/photo-1581578731117-104f8a74695b?auto=format&fit=crop&w=800&q=80';
  if (t.includes('replace') || t.includes('remove') || t.includes('install') || t.includes('bearing') || t.includes('seal') || t.includes('valve') || t.includes('pump')) 
    return 'https://images.unsplash.com/photo-1530124566582-a618bc2615dc?auto=format&fit=crop&w=800&q=80';
  return 'https://images.unsplash.com/photo-1565514020176-db5b550dd707?auto=format&fit=crop&w=800&q=80';
};

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn'; direction: 'asc' | 'desc' }>({ key: 'rpn', direction: 'desc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);
  const [classicalCopied, setClassicalCopied] = useState(false);

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.component) {
      result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.function) {
      result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const aVal = a[sortConfig.key];
      const bVal = b[sortConfig.key];
      if (aVal === bVal) return 0;
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return aVal.localeCompare(bVal) * multiplier;
      }
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => {
    setSearchFilters(prev => ({ ...prev, [field]: value }));
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };

  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };

  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = 
      editForm.maintenanceTask !== originalItem.maintenanceTask ||
      editForm.failureMode !== originalItem.failureMode ||
      editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = {
       ...editForm,
       rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1),
       inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet
    };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm);
        const finalData = newData.map(item => 
          item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item
        );
        onUpdate(finalData);
      } catch (err) { console.error("Failed to auto-regenerate sheet", err); } finally {
        setRegeneratingIds(prev => {
          const next = new Set(prev);
          next.delete(updatedForm.id);
          return next;
        });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) {
      alert("All items already have inspection sheets generated.");
      return;
    }
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setGeneratingSheets(true);
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { alert("Failed to generate."); } finally { 
      setGeneratingSheets(false); 
      setRegeneratingIds(prev => {
        const next = new Set(prev);
        next.delete(item.id);
        return next;
      });
    }
  };

  const updateItemInMainData = (updatedItem: RCMItem) => {
    const newData = data.map(d => d.id === updatedItem.id ? updatedItem : d);
    onUpdate(newData);
  };

  const handleDeleteStep = (idx: number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = sheet.steps.filter((_, i) => i !== idx).map((s, i) => ({ ...s, step: i + 1 }));
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleAddStep = () => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet || { responsibility: 'Operator', estimatedTime: '10m', safetyPrecautions: 'Standard PPE', toolsRequired: 'None', steps: [] };
    const newStep: InspectionStep = {
      step: (sheet.steps?.length || 0) + 1,
      description: 'New inspection action',
      criteria: 'Pass/Fail criteria',
      technique: 'Visual'
    };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: [...(sheet.steps || []), newStep] } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
    setEditingStepIdx((sheet.steps?.length || 0));
  };

  const handleUpdateStepField = (idx: number, field: keyof InspectionStep, value: string | number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = [...sheet.steps];
    newSteps[idx] = { ...newSteps[idx], [field]: value };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleCopy = async () => {
    const headers = [
      "Component", "Function", "Functional Failure", "Failure Mode", "Effect", 
      "Consequence Cat.", "ISO 14224 Code",
      "Criticality", "S", "O", "D", "RPN",
      "Proposed Task", "Interval", "Task Type",
      "Step #", "Action", "Method/Technique", "Acceptance Criteria"
    ];
    const rows: string[] = [];
    processedData.forEach(item => {
      const sheet = item.inspectionSheet;
      const baseRow = [
        item.component, item.function, item.functionalFailure, item.failureMode, item.failureEffect,
        item.consequenceCategory, item.iso14224Code,
        item.criticality, item.severity, item.occurrence, item.detection, item.rpn,
        item.maintenanceTask, item.interval, item.taskType
      ];
      if (sheet && sheet.steps && sheet.steps.length > 0) {
        sheet.steps.forEach(step => {
          const stepRow = [step.step, step.description, step.technique, step.criteria];
          const finalRow = [...baseRow, ...stepRow].map(val => {
            const str = String(val || '');
            if (/[\t\n"]/.test(str)) return `"${str.replace(/"/g, '""')}"`;
            return str;
          }).join("\t");
          rows.push(finalRow);
        });
      } else {
        const legacyInfo = sheet?.checkPointDescription || "";
        const stepRow = ["", legacyInfo, sheet?.type || "", sheet?.criteriaLimits || ""];
        const finalRow = [...baseRow, ...stepRow].map(val => {
          const str = String(val || '');
          if (/[\t\n"]/.test(str)) return `"${str.replace(/"/g, '""')}"`;
          return str;
        }).join("\t");
        rows.push(finalRow);
      }
    });
    const text = [headers.join("\t"), ...rows].join("\n");
    try { 
      await navigator.clipboard.writeText(text); 
      setCopied(true); 
      setTimeout(() => setCopied(false), 2000); 
    } catch (err) { console.error(err); }
  };

  const handleClassicalCopy = async () => {
    const headers = [
      "Component", "Explanation", "Failure mode", "Proposed Task", "Frequency", "Type of task", "Step number", "Actions"
    ];
    const rows: string[] = [];

    let lastComponent = "";

    processedData.forEach(item => {
      const sheet = item.inspectionSheet;
      const isNewComponent = item.component !== lastComponent;
      const componentToShow = isNewComponent ? item.component : "";
      const explanationToShow = isNewComponent ? (item.componentIntel?.description || "") : "";
      lastComponent = item.component;

      const baseInfo = [
        componentToShow,
        explanationToShow,
        item.failureMode,
        item.maintenanceTask,
        item.interval,
        item.taskType
      ];

      if (sheet && sheet.steps && sheet.steps.length > 0) {
        sheet.steps.forEach((step, idx) => {
          // Only show failure mode/component info on the first step row of this item
          const rowData = idx === 0 
            ? [...baseInfo, step.step, step.description]
            : ["", "", "", "", "", "", step.step, step.description];

          const finalRow = rowData.map(val => {
            const str = String(val || '');
            if (/[\t\n"]/.test(str)) return `"${str.replace(/"/g, '""')}"`;
            return str;
          }).join("\t");
          rows.push(finalRow);
        });
      } else {
        const finalRow = [...baseInfo, "", ""].map(val => {
          const str = String(val || '');
          if (/[\t\n"]/.test(str)) return `"${str.replace(/"/g, '""')}"`;
          return str;
        }).join("\t");
        rows.push(finalRow);
      }
    });

    const text = [headers.join("\t"), ...rows].join("\n");
    try { 
      await navigator.clipboard.writeText(text); 
      setClassicalCopied(true); 
      setTimeout(() => setClassicalCopied(false), 2000); 
    } catch (err) { console.error(err); }
  };

  const handleMatrixClick = (s: number, o: number) => {
    if (matrixFilter?.s === s && matrixFilter?.o === o) {
      setMatrixFilter(null);
    } else {
      setMatrixFilter({ s, o });
    }
  };

  const handleBarClick = (id: string) => {
    if (barFilter === id) {
      setBarFilter(null);
    } else {
      setBarFilter(id);
    }
  };

  const clearAllFilters = () => {
    setMatrixFilter(null);
    setBarFilter(null);
    setSearchFilters({ component: '', function: '', failureMode: '', consequenceCategory: '', iso14224Code: '' });
    setSortConfig({ key: 'rpn', direction: 'desc' });
  };

  const topRisks = data
    .sort((a, b) => (b.rpn || 0) - (a.rpn || 0))
    .slice(0, 5)
    .map(item => ({
      id: item.id,
      name: (item.failureMode || '').length > 20 ? (item.failureMode || '').substring(0, 20) + '...' : (item.failureMode || ''),
      rpn: item.rpn || 0
    }));

  const renderSortIcon = (key: keyof RCMItem | 'rpn') => {
    if (sortConfig.key !== key) return <ArrowUpDown size={14} className="text-slate-300" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600" /> : <ArrowDown size={14} className="text-indigo-600" />;
  };

  const renderComponentIntelModal = () => {
    if (!selectedIntel) return null;
    const intel = selectedIntel.componentIntel;

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-3xl shadow-2xl w-full max-w-lg overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 border border-slate-100">
          <div className="bg-slate-900 px-8 py-6 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30">
                <Info size={24} className="text-indigo-200" />
              </div>
              <div>
                <h3 className="font-black text-xl leading-none uppercase tracking-tight">{selectedIntel.component}</h3>
                <p className="text-[10px] text-slate-400 mt-1.5 uppercase tracking-widest font-bold">Physical Component Intel</p>
              </div>
            </div>
            <div className="flex items-center gap-2">
              <button
                onClick={handleInternalUndo}
                disabled={!canUndo}
                className={`p-2 rounded-full transition-all ${
                  canUndo ? 'hover:bg-white/10 text-white' : 'text-slate-600 opacity-20'
                }`}
                title="Undo last action"
              >
                <Undo2 size={24} />
              </button>
              <button onClick={() => setSelectedIntel(null)} className="hover:bg-white/10 p-2 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>
          </div>

          <div className="p-8 space-y-8 bg-slate-50/30">
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-indigo-600">
                <FileText size={18} />
                <h4 className="text-xs font-black uppercase tracking-widest">Description</h4>
              </div>
              <p className="text-sm text-slate-700 leading-relaxed font-medium bg-white p-4 rounded-2xl border border-slate-100 shadow-sm italic">
                {intel?.description || "No description provided."}
              </p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="space-y-3">
                <div className="flex items-center gap-2 text-amber-600">
                  <MapPin size={18} />
                  <h4 className="text-xs font-black uppercase tracking-widest">Location</h4>
                </div>
                <p className="text-xs text-slate-600 leading-relaxed font-semibold bg-white p-4 rounded-2xl border border-slate-100 shadow-sm min-h-[80px]">
                  {intel?.location || "Location context unavailable."}
                </p>
              </div>
              <div className="space-y-3">
                <div className="flex items-center gap-2 text-emerald-600">
                  <Eye size={18} />
                  <h4 className="text-xs font-black uppercase tracking-widest">Visual Cues</h4>
                </div>
                <p className="text-xs text-slate-600 leading-relaxed font-semibold bg-white p-4 rounded-2xl border border-slate-100 shadow-sm min-h-[80px]">
                  {intel?.visualCues || "Identification cues not defined."}
                </p>
              </div>
            </div>
          </div>

          <div className="px-8 py-6 bg-white border-t border-slate-50 flex justify-end">
             <button 
               onClick={() => setSelectedIntel(null)}
               className="px-8 py-3 bg-slate-900 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-lg active:scale-95"
             >
               Understood
             </button>
          </div>
        </div>
      </div>
    );
  };

  const renderInspectionSheet = () => {
    if (!viewSheet || !viewSheet.item.inspectionSheet) return null;
    const { item } = viewSheet;
    const sheet = item.inspectionSheet;
    const taskImage = getTaskImage(item.maintenanceTask);
    const steps = sheet.steps || [];

    return (
      <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 backdrop-blur-sm p-4 transition-all">
        <div className="bg-white rounded-xl shadow-2xl w-full max-w-7xl h-[90vh] flex flex-col animate-in zoom-in-95 duration-200">
          <div className="bg-slate-900 px-8 py-5 flex justify-between items-center text-white shrink-0 rounded-t-xl">
            <div className="flex items-center gap-4">
              <div className="p-2.5 bg-indigo-500/20 rounded-xl border border-indigo-500/30">
                 <ClipboardList size={24} className="text-indigo-200" />
              </div>
              <div>
                <h3 className="font-bold text-xl leading-tight">Maintenance Inspection Procedure</h3>
                <p className="text-sm text-slate-400 font-mono mt-0.5">{item.component} • {item.id.split('-').pop()?.toUpperCase()}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <button
                onClick={handleInternalUndo}
                disabled={!canUndo}
                className={`p-2.5 rounded-xl transition-all ${
                  canUndo ? 'bg-white/10 text-white hover:bg-white/20' : 'text-slate-600 opacity-20'
                }`}
                title="Undo last action"
              >
                <Undo2 size={24} />
              </button>
              <button onClick={() => setViewSheet(null)} className="hover:bg-white/10 p-2 rounded-full transition-colors">
                <X size={24} />
              </button>
            </div>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar bg-slate-50 p-8">
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-8">
              <div className="bg-white rounded-xl border border-slate-200 shadow-sm col-span-1 lg:col-span-2 flex flex-col sm:flex-row overflow-hidden group">
                 <div className="w-full sm:w-1/3 relative h-48 sm:h-auto overflow-hidden bg-slate-200">
                    <img src={taskImage} alt={item.maintenanceTask} className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110" />
                    <div className="absolute inset-0 bg-gradient-to-t from-slate-900/60 to-transparent sm:bg-indigo-900/10 sm:group-hover:bg-transparent transition-colors"></div>
                    <div className="absolute top-3 left-3 bg-white/95 backdrop-blur-md px-2.5 py-1 rounded-md text-[10px] font-bold uppercase tracking-wider text-slate-800 shadow-sm border border-slate-100">{item.taskType}</div>
                 </div>
                 <div className="flex-1 p-6 flex flex-col justify-between">
                    <div>
                        <div className="flex items-start justify-between mb-2">
                           <div>
                                <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400">Target Failure Mode</span>
                                <h4 className="text-lg font-bold text-slate-800 leading-snug mt-1">{item.failureMode}</h4>
                                <div className="flex gap-2 mt-2">
                                  <span className="text-[10px] font-bold bg-slate-100 text-slate-600 px-2 py-0.5 rounded border border-slate-200 flex items-center gap-1"><ShieldCheck size={10} /> {item.consequenceCategory}</span>
                                  <span className="text-[10px] font-bold bg-indigo-50 text-indigo-600 px-2 py-0.5 rounded border border-indigo-100 flex items-center gap-1"><Tag size={10} /> {item.iso14224Code}</span>
                                </div>
                           </div>
                        </div>
                        <div className="mt-4">
                           <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 block mb-1">Maintenance Task</span>
                           <p className="text-sm font-medium text-slate-700 bg-slate-50 p-3 rounded-lg border border-slate-100 leading-relaxed">{item.maintenanceTask}</p>
                        </div>
                    </div>
                    <div className="mt-6 flex items-center gap-6 border-t border-slate-100 pt-4">
                        <div>
                           <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 block mb-0.5">Frequency</span>
                           <span className="inline-flex items-center gap-1.5 text-sm font-bold text-indigo-600 bg-indigo-50 px-2 py-0.5 rounded"><Clock size={12} /> {item.interval}</span>
                        </div>
                        <div className="h-8 w-px bg-slate-100"></div>
                        <div>
                           <span className="text-[10px] font-bold uppercase tracking-wider text-slate-400 block mb-0.5">Risk Level (RPN)</span>
                           <span className={`text-sm font-bold flex items-center gap-1.5 ${getScoreColor(item.severity || 0)}`}><AlertOctagon size={14} /> {item.rpn}</span>
                        </div>
                    </div>
                 </div>
              </div>

              <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm space-y-5 flex flex-col justify-center">
                 <div className="flex items-start gap-3">
                    <div className="p-2 bg-red-50 text-red-600 rounded-lg shrink-0"><ShieldAlert size={20} /></div>
                    <div>
