import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-extrabold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1 border-b border-slate-100 pb-1">
              <h4 className={`font-black text-[11px] uppercase tracking-widest ${role === 'model' ? 'text-indigo-600' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-2 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    // Immediate, silent reset for maximum efficiency
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        comp: i.component,
        fail: i.failureMode,
        rpn: i.rpn,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const historyStr = messages.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.text}`).join('\n');

      const prompt = `
        CONVERSATION HISTORY:
        ${historyStr}

        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER QUESTION/REQUEST: ${userMsg}

        RELIABILITY LEAD INSTRUCTIONS:
        - Act as "MIRA", the Senior Maintenance Intelligence Reliability Assistant.
        - Answer technical questions conversationally but strictly based on SAE JA1011.
        - Propose <ACTION> triggers only when specifically asked to generate or update items.
        - Keep failure modes in [Mechanism] due to [Cause] format.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You are professional, analytical, and highly precise."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis integrated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA is currently synchronizing with the database. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'New Subsystem',
        function: proposal.item.function || 'Perform intended work',
        functionalFailure: proposal.item.functionalFailure || 'Loss of function',
        failureMode: proposal.item.failureMode || 'Wear due to Cause',
        failureEffect: proposal.item.failureEffect || 'Local/System effects',
        consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'Wear',
        criticality: proposal.item.criticality || 'Medium',
        severity: proposal.item.severity || 5,
        occurrence: proposal.item.occurrence || 3,
        detection: proposal.item.detection || 3,
        rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection/Task',
        interval: proposal.item.interval || 'Weekly',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const unapplied = message.proposals.filter(p => !p.applied && p.item);
    if (unapplied.length === 0) return;

    let newData = data ? [...data] : [];

    unapplied.forEach(proposal => {
      if (!proposal.item) return;
      if (proposal.type === 'ADD') {
        const newItem: RCMItem = {
          id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item.component || 'New Subsystem',
          function: proposal.item.function || 'Intended Work',
          functionalFailure: proposal.item.functionalFailure || 'Total Failure',
          failureMode: proposal.item.failureMode || 'Wear due to Cause',
          failureEffect: proposal.item.failureEffect || 'Local Effect',
          consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
          iso14224Code: proposal.item.iso14224Code || 'Wear',
          criticality: proposal.item.criticality || 'Medium',
          severity: proposal.item.severity || 5,
          occurrence: proposal.item.occurrence || 3,
          detection: proposal.item.detection || 3,
          rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
          maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
          interval: proposal.item.interval || 'Monthly',
          taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
          ...proposal.item,
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
          if (isMatch) {
            const updated = { ...item, ...proposal.item };
            updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
            return updated;
          }
          return item;
        });
      } 
      else if (proposal.type === 'DELETE' && proposal.item.id) {
        newData = newData.filter(item => item && item.id !== proposal.item.id);
      }
    });

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return { ...m, proposals: m.proposals.map(p => ({ ...p, applied: true })) };
      }
      return m;
    }));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Engineering Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Sync All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[450px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[2rem] p-5 shadow-sm transition-all border-l-[10px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[12px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'New Subsystem'}
                        </span>
                      </div>

                      <div className="space-y-3">
                        <div className="text-[12px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-3 rounded-2xl border border-slate-100 italic">
                          "{p.item?.failureMode || 'Drafting failure mode...'}"
                        </div>

                        {!p.applied && p.item && (
                          <div className="flex flex-wrap items-center gap-4 pt-2 border-t border-slate-100 mt-2">
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400">
                              <AlertTriangle size={12} /> RPN: <span className="text-slate-900">{(p.item?.severity || 0) * (p.item?.occurrence || 0) * (p.item?.detection || 0)}</span>
                            </div>
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400">
                              <Tag size={12} className="text-emerald-500" /> <span className="text-emerald-700 uppercase">{p.item?.iso14224Code || 'TBD'}</span>
                            </div>
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-indigo-600 transition-all shrink-0 shadow-xl shadow-slate-200 group/btn active:scale-95"
                       title="Implement Directive"
                     >
                       <Plus size={22} className="group-hover/btn:scale-110 transition-transform" />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[720px] h-[820px] bg-white rounded-[4rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          {/* PREMIUM HEADER - "MIRA" BRANDING */}
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-10 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-10 opacity-5 pointer-events-none">
                <Cpu size={120} className="rotate-12" />
            </div>

            <div className="flex items-center gap-6 relative z-10">
              <div className="p-5 bg-indigo-500/10 rounded-[2rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={32} className="text-indigo-400 animate-pulse" />
              </div>
              <div>
                <h3 className="font-black text-3xl tracking-tighter leading-none uppercase flex items-center gap-3">
                    MIRA
                    <span className="text-[10px] px-2 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest">v4.2</span>
                </h3>
                <div className="flex items-center gap-2 mt-3">
                   <div className="w-2.5 h-2.5 rounded-full bg-emerald-500 animate-pulse ring-4 ring-emerald-500/20"></div>
                   <span className="text-[10px] text-slate-400 font-black uppercase tracking-[0.25em]">Reliability Intelligence Assistant</span>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-3 rounded-full transition-all group active:scale-95"
            >
              <ChevronDown size={36} className="group-hover:translate-y-1 transition-transform" />
            </button>
          </div>

          {/* CHAT INTERFACE AREA */}
          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-10 space-y-12 bg-slate-50/50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-12 space-y-10">
                <div className="w-32 h-32 bg-white text-indigo-600 rounded-[3rem] flex items-center justify-center shadow-2xl -rotate-6 hover:rotate-0 transition-all duration-700 border border-indigo-50 ring-8 ring-indigo-50/30">
                    <Layers size={64} className="opacity-80" />
                </div>
                <div className="space-y-6">
                  <p className="text-3xl font-black text-slate-900 tracking-tighter uppercase">Initialize Consultation</p>
                  <p className="text-[16px] text-slate-500 leading-relaxed px-12 font-medium italic opacity-80">
                    "Sync with ISO 14224 for my pump analysis" or "Help me draft a maintenance strategy for conveyor belts"
                  </p>
                  <div className="pt-10 flex flex-wrap justify-center gap-4">
                    <span className="px-5 py-2.5 bg-white border border-slate-200 rounded-[1.2rem] text-[10px] font-black text-slate-500 shadow-sm uppercase tracking-widest hover:border-indigo-200 transition-colors">Risk Assessment</span>
                    <span className="px-5 py-2.5 bg-white border border-slate-200 rounded-[1.2rem] text-[10px] font-black text-slate-500 shadow-sm uppercase tracking-widest hover:border-indigo-200 transition-colors">Strategy Logic</span>
                  </div>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-8 rounded-[2.8rem] shadow-xl leading-relaxed relative ${
                  m.role === 'user' 
                    ? 'bg-slate-900 text-white rounded-br-none font-bold text-[16px] shadow-slate-200' 
                    : 'bg-white text-slate-800 border-2 border-indigo-50 rounded-bl-none shadow-indigo-100/10'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border-2 border-indigo-50 p-8 rounded-[2.8rem] rounded-bl-none shadow-xl flex items-center gap-6">
                  <div className="flex gap-2.5">
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">MIRA is Synthesizing</span>
                </div>
              </div>
            )}
          </div>

          {/* INPUT STATION AREA */}
          <div className="p-10 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-6">
              {/* RESET BUTTON - BOTTOM LEFT POSITION */}
              <button 
                onClick={handleReset}
                className="p-6 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[2rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 active:scale-90 shadow-inner group"
                title="Clear Knowledge Threads"
              >
                <RotateCcw size={28} className="group-hover:-rotate-180 transition-transform duration-500" />
              </button>

              <div className="flex-1 relative group">
                <input 
                  type="text" 
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleSend()}
                  placeholder="Consult MIRA for technical guidance..."
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] px-10 py-6 text-[16px] focus:ring-8 focus:ring-indigo-600/5 focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner"
                />
              </div>

              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="p-6 bg-indigo-600 text-white rounded-[2rem] hover:bg-indigo-700 active:scale-95 disabled:opacity-30 transition-all shadow-2xl shadow-indigo-200 flex items-center justify-center group"
              >
                <Send size={32} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* FLOATING TRIGGER BUTTON - HIGH VISIBILITY */}
      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className={`relative w-24 h-24 rounded-[2.8rem] flex items-center justify-center text-white shadow-[0_25px_60px_rgba(79,70,229,0.4)] transition-all hover:scale-110 active:scale-95 z-[60] border-4 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}
      >
        {!isOpen && (
          <span className="absolute inset-0 rounded-[2.8rem] bg-indigo-600 animate-ping opacity-30 pointer-events-none scale-125"></span>
        )}
        {isOpen ? <X size={44} /> : <Bot size={44} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-9 h-9 bg-emerald-500 border-4 border-white rounded-2xl flex items-center justify-center shadow-lg">
            <Sparkles size={16} className="text-white fill-white" />
          </div>
        )}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-extrabold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1 border-b border-slate-100 pb-1">
              <h4 className={`font-black text-[11px] uppercase tracking-widest ${role === 'model' ? 'text-indigo-600' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-2 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        comp: i.component,
        fail: i.failureMode,
        rpn: i.rpn,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const historyStr = messages.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.text}`).join('\n');

      const prompt = `
        CONVERSATION HISTORY:
        ${historyStr}

        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER QUESTION/REQUEST: ${userMsg}

        RELIABILITY LEAD INSTRUCTIONS:
        - Act as "MIRA", the Senior Maintenance Intelligence Reliability Assistant.
        - Answer technical questions conversationally but strictly based on SAE JA1011.
        - Propose <ACTION> triggers only when specifically asked to generate or update items.
        - Keep failure modes in [Mechanism] due to [Cause] format.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You are professional, analytical, and highly precise."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis integrated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA is currently synchronizing with the database. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'New Subsystem',
        function: proposal.item.function || 'Perform intended work',
        functionalFailure: proposal.item.functionalFailure || 'Loss of function',
        failureMode: proposal.item.failureMode || 'Wear due to Cause',
        failureEffect: proposal.item.failureEffect || 'Local/System effects',
        consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'Wear',
        criticality: proposal.item.criticality || 'Medium',
        severity: proposal.item.severity || 5,
        occurrence: proposal.item.occurrence || 3,
        detection: proposal.item.detection || 3,
        rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection/Task',
        interval: proposal.item.interval || 'Weekly',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const unapplied = message.proposals.filter(p => !p.applied && p.item);
    if (unapplied.length === 0) return;

    let newData = data ? [...data] : [];

    unapplied.forEach(proposal => {
      if (!proposal.item) return;
      if (proposal.type === 'ADD') {
        const newItem: RCMItem = {
          id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item.component || 'New Subsystem',
          function: proposal.item.function || 'Intended Work',
          functionalFailure: proposal.item.functionalFailure || 'Total Failure',
          failureMode: proposal.item.failureMode || 'Wear due to Cause',
          failureEffect: proposal.item.failureEffect || 'Local Effect',
          consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
          iso14224Code: proposal.item.iso14224Code || 'Wear',
          criticality: proposal.item.criticality || 'Medium',
          severity: proposal.item.severity || 5,
          occurrence: proposal.item.occurrence || 3,
          detection: proposal.item.detection || 3,
          rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
          maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
          interval: proposal.item.interval || 'Monthly',
          taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
          ...proposal.item,
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
          if (isMatch) {
            const updated = { ...item, ...proposal.item };
            updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
            return updated;
          }
          return item;
        });
      } 
      else if (proposal.type === 'DELETE' && proposal.item.id) {
        newData = newData.filter(item => item && item.id !== proposal.item.id);
      }
    });

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return { ...m, proposals: m.proposals.map(p => ({ ...p, applied: true })) };
      }
      return m;
    }));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Engineering Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Sync All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[450px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[2rem] p-5 shadow-sm transition-all border-l-[10px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[12px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'New Subsystem'}
                        </span>
                      </div>

                      <div className="space-y-3">
                        <div className="text-[12px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-3 rounded-2xl border border-slate-100 italic">
                          "{p.item?.failureMode || 'Drafting failure mode...'}"
                        </div>

                        {!p.applied && p.item && (
                          <div className="flex flex-wrap items-center gap-4 pt-2 border-t border-slate-100 mt-2">
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400">
                              <AlertTriangle size={12} /> RPN: <span className="text-slate-900">{(p.item?.severity || 0) * (p.item?.occurrence || 0) * (p.item?.detection || 0)}</span>
                            </div>
                            <div className="flex items-center gap-1.5 text-[10px] font-black text-slate-400">
                              <Tag size={12} className="text-emerald-500" /> <span className="text-emerald-700 uppercase">{p.item?.iso14224Code || 'TBD'}</span>
                            </div>
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-3 bg-slate-900 text-white rounded-2xl hover:bg-indigo-600 transition-all shrink-0 shadow-xl shadow-slate-200 group/btn active:scale-95"
                       title="Implement Directive"
                     >
                       <Plus size={22} className="group-hover/btn:scale-110 transition-transform" />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[720px] h-[820px] bg-white rounded-[4rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          {/* REFINED HEADER - "MIRA" WITH EXPLANATION */}
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-8 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-10 opacity-5 pointer-events-none">
                <Cpu size={120} className="rotate-12" />
            </div>

            <div className="flex items-center gap-5 relative z-10">
              <div className="p-3 bg-indigo-500/10 rounded-[1.5rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={20} className="text-indigo-400" />
              </div>
              <div>
                <div className="flex items-center gap-3">
                    <h3 className="font-black text-2xl tracking-tighter leading-none uppercase">MIRA</h3>
                    <span className="text-[9px] px-1.5 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest opacity-80">CO-PILOT</span>
                </div>
                <div className="mt-2.5 max-w-[400px]">
                   <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.1em] leading-relaxed">
                     Maintenance Intelligence Reliability Assistant
                   </p>
                   <p className="text-[9px] text-indigo-300 font-bold uppercase tracking-tight mt-0.5 opacity-60">
                     Advanced AI support for automated RCM/FMEA analysis
                   </p>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-2.5 rounded-full transition-all group active:scale-95"
            >
              <ChevronDown size={32} className="group-hover:translate-y-1 transition-transform" />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-10 space-y-12 bg-slate-50/50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-12 space-y-10">
                <div className="w-24 h-24 bg-white text-indigo-600 rounded-[2rem] flex items-center justify-center shadow-2xl -rotate-6 hover:rotate-0 transition-all duration-700 border border-indigo-50 ring-8 ring-indigo-50/30">
                    <Layers size={48} className="opacity-80" />
                </div>
                <div className="space-y-6">
                  <p className="text-2xl font-black text-slate-900 tracking-tighter uppercase">Initialize Consultation</p>
                  <p className="text-[14px] text-slate-500 leading-relaxed px-12 font-medium italic opacity-80">
                    Consult with MIRA to refine component analysis, generate failure modes, or validate strategy logic.
                  </p>
                  <div className="pt-8 flex flex-wrap justify-center gap-4">
                    <span className="px-5 py-2.5 bg-white border border-slate-200 rounded-[1.2rem] text-[10px] font-black text-slate-500 shadow-sm uppercase tracking-widest">Risk Assessment</span>
                    <span className="px-5 py-2.5 bg-white border border-slate-200 rounded-[1.2rem] text-[10px] font-black text-slate-500 shadow-sm uppercase tracking-widest">Strategy Logic</span>
                  </div>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-8 rounded-[2.8rem] shadow-xl leading-relaxed relative ${
                  m.role === 'user' 
                    ? 'bg-slate-900 text-white rounded-br-none font-bold text-[16px] shadow-slate-200' 
                    : 'bg-white text-slate-800 border-2 border-indigo-50 rounded-bl-none shadow-indigo-100/10'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border-2 border-indigo-50 p-8 rounded-[2.8rem] rounded-bl-none shadow-xl flex items-center gap-6">
                  <div className="flex gap-2.5">
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-3.5 h-3.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[11px] font-black text-slate-400 uppercase tracking-[0.3em]">Synthesizing Analysis</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-10 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-6">
              <button 
                onClick={handleReset}
                className="p-6 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[2rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 active:scale-90 shadow-inner group"
                title="Clear Consultation"
              >
                <RotateCcw size={24} />
              </button>

              <div className="flex-1 relative group">
                <input 
                  type="text" 
                  value={input}
                  onChange={e => setInput(e.target.value)}
                  onKeyDown={e => e.key === 'Enter' && handleSend()}
                  placeholder="Consult MIRA for technical guidance..."
                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-[2.5rem] px-10 py-6 text-[16px] focus:ring-8 focus:ring-indigo-600/5 focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner"
                />
              </div>

              <button 
                onClick={handleSend} 
                disabled={!input.trim() || isLoading} 
                className="p-6 bg-indigo-600 text-white rounded-[2rem] hover:bg-indigo-700 active:scale-95 disabled:opacity-30 transition-all shadow-2xl shadow-indigo-200 flex items-center justify-center group"
              >
                <Send size={28} />
              </button>
            </div>
          </div>
        </div>
      )}

      {/* REFINED TRIGGER BUTTON - SMALLER & NO BLINKING */}
      <button 
        onClick={() => setIsOpen(!isOpen)} 
        className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-[0_15px_40px_rgba(79,70,229,0.3)] transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}
      >
        {isOpen ? <X size={28} /> : <Bot size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 border-2 border-white rounded-lg flex items-center justify-center shadow-lg">
            <Sparkles size={10} className="text-white fill-white" />
          </div>
        )}
      </button>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();

        const formatInline = (content: string) => {
          return content.split(/(\*\*.*?\*\*)/g).map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={idx + '-' + i} className="font-extrabold">{part.slice(2, -2)}</strong>;
            }
            return part;
          });
        };

        if (trimmed.startsWith('###')) {
          return (
            <div key={idx} className="mt-4 mb-1 border-b border-slate-100 pb-1">
              <h4 className={`font-black text-[11px] uppercase tracking-widest ${role === 'model' ? 'text-indigo-600' : 'text-white underline'}`}>
                {formatInline(trimmed.replace(/^###\s*/, ''))}
              </h4>
            </div>
          );
        }

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          const content = trimmed.replace(/^[*|-]\s*/, '');
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 mt-2 w-1 h-1 rounded-full bg-current ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}></span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(content)}</span>
            </div>
          );
        }

        const numMatch = trimmed.match(/^(\d+)\.\s(.*)/);
        if (numMatch) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <span className={`shrink-0 font-bold text-[10px] mt-0.5 ${role === 'model' ? 'opacity-40' : 'opacity-70'}`}>
                {numMatch[1]}.
              </span>
              <span className="flex-1 text-[13px] font-medium">{formatInline(numMatch[2])}</span>
            </div>
          );
        }

        if (!trimmed) return <div key={idx} className="h-1"></div>;

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{formatInline(line)}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        comp: i.component,
        fail: i.failureMode,
        rpn: i.rpn,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const historyStr = messages.map(m => `${m.role === 'user' ? 'User' : 'Assistant'}: ${m.text}`).join('\n');

      const prompt = `
        CONVERSATION HISTORY:
        ${historyStr}

        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER QUESTION/REQUEST: ${userMsg}

        RELIABILITY LEAD INSTRUCTIONS:
        - Act as "MIRA", the Senior Maintenance Intelligence Reliability Assistant.
        - Answer technical questions conversationally but strictly based on SAE JA1011.
        - Propose <ACTION> triggers only when specifically asked to generate or update items.
        - Keep failure modes in [Mechanism] due to [Cause] format.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You are professional, analytical, and highly precise."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis integrated.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA is currently synchronizing with the database. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'New Subsystem',
        function: proposal.item.function || 'Perform intended work',
        functionalFailure: proposal.item.functionalFailure || 'Loss of function',
        failureMode: proposal.item.failureMode || 'Wear due to Cause',
        failureEffect: proposal.item.failureEffect || 'Local/System effects',
        consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'Wear',
        criticality: proposal.item.criticality || 'Medium',
        severity: proposal.item.severity || 5,
        occurrence: proposal.item.occurrence || 3,
        detection: proposal.item.detection || 3,
        rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection/Task',
        interval: proposal.item.interval || 'Weekly',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        ...proposal.item,
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item };
          updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const unapplied = message.proposals.filter(p => !p.applied && p.item);
    if (unapplied.length === 0) return;

    let newData = data ? [...data] : [];

    unapplied.forEach(proposal => {
      if (!proposal.item) return;
      if (proposal.type === 'ADD') {
        const newItem: RCMItem = {
          id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item.component || 'New Subsystem',
          function: proposal.item.function || 'Intended Work',
          functionalFailure: proposal.item.functionalFailure || 'Total Failure',
          failureMode: proposal.item.failureMode || 'Wear due to Cause',
          failureEffect: proposal.item.failureEffect || 'Local Effect',
          consequenceCategory: proposal.item.consequenceCategory || 'Evident - Operational',
          iso14224Code: proposal.item.iso14224Code || 'Wear',
          criticality: proposal.item.criticality || 'Medium',
          severity: proposal.item.severity || 5,
          occurrence: proposal.item.occurrence || 3,
          detection: proposal.item.detection || 3,
          rpn: (proposal.item.severity || 5) * (proposal.item.occurrence || 3) * (proposal.item.detection || 3),
          maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
          interval: proposal.item.interval || 'Monthly',
          taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
          ...proposal.item,
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE' && (proposal.item.id || proposal.item.component)) {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
          if (isMatch) {
            const updated = { ...item, ...proposal.item };
            updated.rpn = (updated.severity || 1) * (updated.occurrence || 1) * (updated.detection || 1);
            return updated;
          }
          return item;
        });
      } 
      else if (proposal.type === 'DELETE' && proposal.item.id) {
        newData = newData.filter(item => item && item.id !== proposal.item.id);
      }
    });

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return { ...m, proposals: m.proposals.map(p => ({ ...p, applied: true })) };
      }
      return m;
    }));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Engineering Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Sync All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[1.5rem] p-4 shadow-sm transition-all border-l-[8px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[11px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'New Subsystem'}
                        </span>
                      </div>

                      <div className="space-y-2">
                        <div className="text-[11px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-2 rounded-xl border border-slate-100 italic">
                          "{p.item?.failureMode || 'Drafting failure mode...'}"
                        </div>

                        {!p.applied && p.item && (
                          <div className="flex flex-wrap items-center gap-3 pt-2 border-t border-slate-100 mt-1">
                            <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                              <AlertTriangle size={10} /> RPN: <span className="text-slate-900">{(p.item?.severity || 0) * (p.item?.occurrence || 0) * (p.item?.detection || 0)}</span>
                            </div>
                            <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                              <Tag size={10} className="text-emerald-500" /> <span className="text-emerald-700 uppercase">{p.item?.iso14224Code || 'TBD'}</span>
                            </div>
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg shadow-slate-200 group/btn active:scale-95"
                       title="Implement Directive"
                     >
                       <Plus size={18} className="group-hover/btn:scale-110 transition-transform" />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[650px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          {/* HEADER - "MIRA" WITH EXPLANATION (COMPACTED) */}
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-6 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none">
                <Cpu size={80} className="rotate-12" />
            </div>

            <div className="flex items-center gap-4 relative z-10">
              <div className="p-2 bg-indigo-500/10 rounded-[1.2rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl tracking-tighter leading-none uppercase">MIRA</h3>
                    <span className="text-[8px] px-1.5 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest opacity-80 uppercase">Co-pilot</span>
                </div>
                <div className="mt-1.5 max-w-[320px]">
                   <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] leading-tight">
                     Reliability Intelligence Assistant
                   </p>
                   <p className="text-[8px] text-indigo-300 font-bold uppercase tracking-tight mt-0.5 opacity-60">
                     Advanced SAE JA1011 Support
                   </p>
                </div>
              </div>
            </div>
            <button 
              onClick={() => setIsOpen(false)} 
              className="hover:bg-white/10 p-2 rounded-full transition-all group active:scale-95"
            >
              <ChevronDown size={28} className="group-hover:translate-y-1 transition-transform" />
            </button>
          </div>

          <div 
            ref={scrollRef} 
            onScroll={handleScroll}
            className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar"
          >
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[1.8rem] flex items-center justify-center shadow-2xl -rotate-3 hover:rotate-0 transition-all duration-700 border border-indigo-50 ring-4 ring-indigo-50/30">
                    <Layers size={36} className="opacity-80" />
                </div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase">Initial Consultation</p>
