          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button 
                onClick={handleReset}
                className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[1.5rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 active:scale-90 shadow-inner group"
                title="Clear Knowledge Threads"
              >
                <RotateCcw size={20} className="group-hover:-rotate-180 transition-transform duration-500" />
              </button>

              <div className="flex-1 relative">
                <input 
                  type="text" 
