                  className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] focus:ring-4 focus:ring-indigo-600/5 focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner"
                />
