  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [optimizedInterval, setOptimizedInterval] = useState(item.interval);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen) {
      setMessages([{
        role: 'assistant',
        content: `I am ready to optimize the maintenance frequency for ${item.component}. \n\nCurrent strategy: ${item.maintenanceTask} set at ${item.interval} intervals. \n\nTo ensure this is technically efficient, we need to consider the P-F Interval (the time from first detection of the failure mechanism to functional failure). \n\nBased on your site experience or manual data, how long does this failure typically take to progress once detected?`
      }]);
    }
  }, [isOpen, item]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isLoading]);

  if (!isOpen) return null;

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userText = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userText }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      const prompt = `
        FAILURE MODE CONTEXT:
        Component: ${item.component}
        Failure Mode: ${item.failureMode}
        Current Task: ${item.maintenanceTask}
        Current Interval: ${item.interval}
        RPN: ${item.rpn} (S:${item.severity}, O:${item.occurrence}, D:${item.detection})

        USER INPUT: ${userText}

        STRICT INSTRUCTIONS:
        1. DO NOT use markdown characters like ** for bolding or # for headers.
        2. Respond in plain, professional English text.
        3. Analyze the user's input regarding P-F interval or MTBF.
        4. Apply RCM Standard SAE JA1011 logic: A task interval should typically be no more than half the P-F interval to be effective.
        5. Recommend a specific "Optimized Interval". 
        6. Wrap ONLY the final recommended interval value in <INTERVAL>Value</INTERVAL> tags (e.g. <INTERVAL>Monthly</INTERVAL>).
        7. Provide a technical explanation of why this frequency is more efficient without using bolding or special symbols.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are an RCM Interval Optimization Engine. You use technical lead times and reliability statistics to calculate effective maintenance frequencies. You avoid all markdown formatting, bolding, and special characters in your output."
        }
      });

      const aiText = response.text || "Calculation error.";
      const intervalMatch = aiText.match(/<INTERVAL>([\s\S]*?)<\/INTERVAL>/);

      if (intervalMatch) {
        setOptimizedInterval(intervalMatch[1].trim());
      }

      setMessages(prev => [...prev, { 
        role: 'assistant', 
        content: aiText.replace(/<INTERVAL>[\s\S]*?<\/INTERVAL>/, '').trim() 
      }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'assistant', content: "MIRA encountered a logic error. Please try again." }]);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-900/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-4xl h-[80vh] flex flex-col overflow-hidden border border-white/20">

        {/* Header */}
        <div className="bg-slate-900 px-8 py-6 flex justify-between items-center text-white shrink-0">
          <div className="flex items-center gap-4">
            <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30">
              <Calculator size={24} className="text-indigo-400" />
            </div>
            <div>
              <h3 className="font-black text-xl uppercase tracking-tighter">Interval Optimization</h3>
              <p className="text-[10px] text-slate-400 uppercase tracking-widest font-bold mt-1">SAE JA1011 Feasibility Engine</p>
            </div>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
            <X size={24} />
          </button>
        </div>

        {/* Content Area */}
        <div className="flex-1 flex overflow-hidden">

          {/* Left Panel: Context & Stats */}
          <div className="w-80 border-r border-slate-100 bg-slate-50/50 p-6 flex flex-col gap-6 shrink-0 overflow-y-auto custom-scrollbar">
            <div>
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 block">Failure Mode Context</span>
              <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm space-y-3">
                <p className="text-xs font-black text-slate-900 uppercase leading-tight">{item.component}</p>
                <p className="text-xs text-slate-500 font-medium italic leading-relaxed">"{item.failureMode}"</p>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2">
              <div className="bg-white p-2.5 rounded-xl border border-slate-100 text-center shadow-sm">
                <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Sev</span>
                <span className="text-sm font-black text-red-600">{item.severity}</span>
              </div>
              <div className="bg-white p-2.5 rounded-xl border border-slate-100 text-center shadow-sm">
                <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Occ</span>
                <span className="text-sm font-black text-amber-600">{item.occurrence}</span>
              </div>
              <div className="bg-white p-2.5 rounded-xl border border-slate-100 text-center shadow-sm">
                <span className="text-[8px] font-black text-slate-400 uppercase block mb-1">Det</span>
                <span className="text-sm font-black text-blue-600">{item.detection}</span>
              </div>
            </div>

            <div className="bg-slate-900 rounded-2xl p-5 text-white shadow-xl shadow-slate-200">
               <div className="flex items-center gap-2 mb-4">
                 <Target size={14} className="text-indigo-400" />
                 <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">Optimization Goal</span>
               </div>
               <div className="space-y-4">
                  <div>
                    <span className="text-[10px] font-bold text-slate-500 uppercase block">Current</span>
                    <span className="text-lg font-black text-slate-300">{item.interval}</span>
                  </div>
                  <div className="h-px bg-slate-800"></div>
                  <div>
                    <span className="text-[10px] font-bold text-indigo-400 uppercase block">Optimized</span>
                    <span className="text-2xl font-black text-white">{optimizedInterval}</span>
                  </div>
               </div>
            </div>

            <div className="mt-auto">
               <div className="flex items-center gap-2 p-3 bg-emerald-50 rounded-xl border border-emerald-100 text-emerald-700">
                  <Activity size={16} className="shrink-0" />
                  <p className="text-[10px] font-bold leading-tight">MIRA is calculating the P-F Curve for this mechanism.</p>
               </div>
            </div>
          </div>

          {/* Right Panel: Chat Dialogue */}
          <div className="flex-1 flex flex-col bg-white">
            <div 
              ref={scrollRef}
              className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar"
            >
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-2 duration-300`}>
                  <div className={`flex gap-3 max-w-[85%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                    <div className={`w-8 h-8 rounded-lg shrink-0 flex items-center justify-center text-white ${m.role === 'user' ? 'bg-indigo-600' : 'bg-slate-900'}`}>
                      {m.role === 'user' ? <User size={16} /> : <Bot size={16} />}
                    </div>
                    <div className={`p-4 rounded-2xl shadow-sm text-sm font-medium leading-relaxed ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-slate-50 text-slate-700 border border-slate-100 rounded-tl-none'}`}>
                      <FormattedChatMessage content={m.content} role={m.role} />
                    </div>
                  </div>
                </div>
              ))}
              {isLoading && (
                <div className="flex justify-start">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100 flex items-center gap-3">
                    <Loader2 size={16} className="animate-spin text-indigo-600" />
                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Simulating Failure Curves...</span>
                  </div>
                </div>
              )}
            </div>

            <div className="p-6 border-t border-slate-100">
               <div className="flex gap-4">
                  <div className="flex-1 relative">
                    <input 
                      type="text" 
                      value={input}
                      onChange={e => setInput(e.target.value)}
                      onKeyDown={e => e.key === 'Enter' && handleSend()}
                      placeholder="Discuss P-F interval or history..."
                      className="w-full bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all font-medium"
                    />
                  </div>
                  <button 
                    onClick={handleSend}
                    disabled={!input.trim() || isLoading}
                    className="p-3 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 disabled:opacity-30 transition-all shadow-lg active:scale-95"
                  >
                    <Send size={20} />
                  </button>
               </div>
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="px-8 py-5 bg-white border-t border-slate-100 flex justify-between items-center shrink-0">
          <div className="flex items-center gap-2 text-slate-400">
            <ShieldCheck className="w-4 h-4" />
            <span className="text-[10px] font-black uppercase tracking-widest">Engineering Decision Support</span>
          </div>
          <div className="flex gap-3">
            <button onClick={onClose} className="px-6 py-2.5 text-slate-500 font-black text-[10px] uppercase tracking-widest hover:bg-slate-50 rounded-lg transition-all">Discard</button>
            <button 
              onClick={() => onApply(optimizedInterval)}
              className="px-8 py-2.5 bg-indigo-600 text-white rounded-lg font-black text-[10px] uppercase tracking-[0.2em] shadow-xl shadow-indigo-100 hover:bg-indigo-700 transition-all flex items-center gap-2"
            >
              <CheckCircle2 size={16} /> Apply Optimized Interval
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
  }, [results, contextText, fileData, studyName, currentStudyId]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      // Check if welcome has been shown
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 1 minute)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        console.log("Auto-saving progress...");
        handleSaveStudy();
      }
    }, 60000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);
    setResults(null);
    setHistory([]);

    try {
      const data = await generateRCMAnalysis(contextText, fileData);
      setResults(data);
    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async () => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: currentResults || [],
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]); // Keep last 30 states
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <WelcomeModal
        isOpen={showWelcome}
        onClose={handleCloseWelcome}
      />
      <SODReference 
        isOpen={showSODReference} 
        onClose={() => setShowSODReference(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <DecisionLogicModal 
        isOpen={showDecisionLogic} 
        onClose={() => setShowDecisionLogic(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">

            <div className="flex items-center gap-6 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              {/* STUNNING BRAND SECTION */}
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6">
                  <Cpu size={22} className="text-indigo-400 group-hover:text-white" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span>
                    <span className="text-[11px] font-black text-slate-400 leading-none">PRO</span>
                  </div>
                </div>
              </div>

              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">
                   {currentStudyId ? "System Repository" : "Temporary Workspace"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <BookOpen size={16} />
                  S/O/D Guide
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <GitBranch size={16} />
                  Logic Tree
                </button>
              </div>

              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>
                ) : (
                   <span className="text-slate-300">{results ? 'Local draft' : ''}</span>
                )}
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={handleUndo}
                  disabled={history.length === 0}
                  className={`p-2.5 rounded-xl transition-all ${
                    history.length > 0 
                      ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' 
                      : 'text-slate-200 cursor-not-allowed'
                  }`}
                  title="Undo last action"
                >
                  <Undo2 size={20} />
                </button>

                <button
                  onClick={handleSaveStudy}
                  disabled={!results && !contextText}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl
                    ${justSaved 
                      ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'
                    }
                    ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}
                  `}
                >
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
