  consequenceCategory: ConsequenceCategory;
  iso14224Code: string;

  severity: number;
  occurrence: number;
  detection: number;
  rpn: number;

  maintenanceTask: string;
  interval: string;
  pfInterval?: string; // New field for reliability optimization
  taskType: 'Condition Monitoring' | 'Time-Based' | 'Run-to-Failure' | 'Redesign' | 'Failure Finding' | 'Lubrication' | 'Servicing' | 'Restoration' | 'Replacement';
  inspectionSheet?: InspectionSheet;
  componentIntel?: ComponentIntel;
  isNew?: boolean;
}

export interface AnalysisStats {
  totalItems: number;
  highRisk: number;
  mediumRisk: number;
  lowRisk: number;
}

export type InputMode = 'manual' | 'upload';

export interface FileData {
  name: string;
  mimeType: string;
  data: string;
}

export interface SavedStudy {
  id: string;
  name: string;
  timestamp: number;
  items: RCMItem[];
  contextText: string;
  fileName?: string;
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { RCMItem, FileData, InspectionSheet } from "../types";

// Define the expected output schema for structured JSON
const rcmSchema: Schema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      component: { 
        type: Type.STRING, 
        description: "Standard component name at Level 3/4 (e.g., 'Main Shaft', 'Mechanical Seal', 'Bearing Housing', 'Drive Motor')." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { type: Type.STRING, description: "Plain-English explanation of what this part is." },
          location: { type: Type.STRING, description: "Where it is typically found on the asset." },
          visualCues: { type: Type.STRING, description: "What to look for (colors, shapes, textures) to identify it." }
        },
        required: ["description", "location", "visualCues"]
      },
      function: { 
        type: Type.STRING,
        description: "The primary function of the component."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "How the component fails to fulfill its function."
      },
      failureMode: { 
        type: Type.STRING,
        description: "Strictly: [Mechanism] due to [Cause]. Example: 'Erosion due to abrasive slurry' or 'Seizure due to loss of lubrication'."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "The immediate impact on safety, environment, and operations."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ],
        description: "SAE JA1011 Consequence classification."
      },
      iso14224Code: {
        type: Type.STRING,
        description: "Standard failure code (e.g., Wear, Corrosion, Fatigue, Overheating, Leakage, Breakage)."
      },
      criticality: { 
        type: Type.STRING, 
        enum: ["High", "Medium", "Low"],
        description: "Qualitative priority."
      },
      severity: {
        type: Type.INTEGER,
        description: "Severity (1-10). If safety is compromised, score 9-10. Major production loss is 8+."
      },
      occurrence: {
        type: Type.INTEGER,
        description: "Occurrence (1-10). Typical frequency in industrial settings."
      },
      detection: {
        type: Type.INTEGER,
        description: "Detection (1-10). 10 is impossible to detect visually."
      },
      maintenanceTask: { 
        type: Type.STRING,
        description: "Recommended maintenance action (e.g., 'Vibration Analysis', 'Scheduled Replacement')."
      },
      interval: { 
        type: Type.STRING,
        description: "Maintenance frequency (e.g., 'Monthly', 'Annual')."
      },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement'
        ],
        description: "Strategy category."
      }
    },
    required: ["component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");

    const ai = new GoogleGenAI({ apiKey });
    const parts: any[] = [];

    if (fileData) {
      parts.push({
        inlineData: { mimeType: fileData.mimeType, data: fileData.data }
      });
      parts.push({ text: "Perform a level-4 component decomposition and RCM study based on this document." });
    }

    if (contextText) {
      parts.push({ text: `Operational Context:\n${contextText}` });
    }

    let avoidanceInstruction = "";
    if (existingItems.length > 0) {
      const existingSummary = existingItems.map(i => `${i.component} (${i.failureMode})`).join(", ");
      avoidanceInstruction = `\n\nIMPORTANT: Avoid duplicating these existing failure modes already analyzed: ${existingSummary}. Focus on discovering ADDITIONAL or missed failure mechanisms and components within the Level 4 scope.`;
    }

    parts.push({
      text: `Perform a COMPREHENSIVE and RIGOROUS RCM/FMECA study. ${avoidanceInstruction}

      ANALYSIS SCOPE:
      - Target Volume: Generate approximately ${existingItems.length > 0 ? '10-15 NEW' : '30-35'} distinct failure mode items.
      - Component Level: Level 3 or 4 (e.g. 'Drive Motor', 'Main Coupling', 'Discharge Valve'). Do not be too granular (screws) or too broad (the whole machine).

      COMPONENT INTEL MANDATE:
      - For every component, provide a layman physical description, typical location, and visual identification cues.

      RISK SCORING (RPN):
      - We require realistic industrial risk assessment. 
      - SEVERITY: If a failure stops production or risks injury, use 8-10.
      - DETECTION: If internal, use 8-10.
      - Aim for RPNs that clearly highlight criticalities (range of 150-500).

      Compliance: SAE JA1011 and ISO 14224.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        seed: 42, 
        thinkingConfig: { thinkingBudget: 24000 },
        systemInstruction: `You are a Senior Maintenance Engineer. You provide professional, comprehensive RCM reports that strike a balance between high-level summaries and exhaustive audits. Your risk assessments are realistic and favor safety/availability.`
      }
    });

    const rawData = JSON.parse(response.text || "[]") as Omit<RCMItem, 'id' | 'rpn'>[];

    return rawData.map((item, index) => {
      const s = item.severity || 8;
      const o = item.occurrence || 5;
      const d = item.detection || 6;
      return { 
        ...item, 
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        id: `rcm-${Date.now()}-${index}-${Math.random().toString(36).substr(2, 9)}`,
        isNew: true
      };
    });

  } catch (error) {
    console.error("RCM Generation Error:", error);
    throw error;
  }
};

export const generateInspectionSheet = async (item: RCMItem): Promise<InspectionSheet> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");
    const ai = new GoogleGenAI({ apiKey });

    const prompt = `Create a technical inspection procedure for: ${item.maintenanceTask} on ${item.component}.
    Ensure 5 clear technical steps with pass/fail criteria.`;

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: inspectionSchema,
        seed: 42,
        thinkingConfig: { thinkingBudget: 4000 },
        systemInstruction: "Technical Procedure Author. Professional and actionable."
      }
    });

    return JSON.parse(response.text || "{}") as InspectionSheet;
  } catch (error) {
    console.error("Inspection Sheet Error", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
  }, [results, contextText, fileData, studyName, currentStudyId]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      // Check if welcome has been shown
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const legacyData = localStorage.getItem('rcm_studies');
        if (legacyData) {
          try {
            const parsed = JSON.parse(legacyData) as SavedStudy[];
            if (Array.isArray(parsed) && parsed.length > 0) {
              await Promise.all(parsed.map(study => saveStudyToDB(study)));
              localStorage.removeItem('rcm_studies');
            }
          } catch (e) {
            console.warn("Failed to parse legacy data", e);
          }
        }
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 1 minute)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        console.log("Auto-saving progress...");
        handleSaveStudy();
      }
    }, 60000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    // If not merging, clear existing results and history
    if (!isMerging) {
      setResults(null);
      setHistory([]);
    } else {
      // If merging, mark all current results as not new
      if (results) {
        setResults(prev => prev ? prev.map(item => ({ ...item, isNew: false })) : null);
      }
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        // Append new data to existing
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async () => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: Date.now(),
      items: (currentResults || []).map(item => ({ ...item, isNew: false })), // Clear 'isNew' flag on save
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      console.error("Save failed", e);
      setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]); // Keep last 30 states
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">

      {/* Modals */}
      <WelcomeModal
        isOpen={showWelcome}
        onClose={handleCloseWelcome}
      />
      <SODReference 
        isOpen={showSODReference} 
        onClose={() => setShowSODReference(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />
      <DecisionLogicModal 
        isOpen={showDecisionLogic} 
        onClose={() => setShowDecisionLogic(false)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0} 
      />

      {/* AI Copilot - Minimal floating UI */}
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <div className={`
        fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <Sidebar 
          studies={savedStudies}
          currentStudyId={currentStudyId}
          onSelect={handleLoadStudy}
          onDelete={handleDeleteStudy}
          onNew={handleNewStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        {/* Header */}
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">

            <div className="flex items-center gap-6 min-w-0">
              <button 
                className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden"
                onClick={() => setIsSidebarOpen(true)}
              >
                <Menu size={24} />
              </button>

              {/* STUNNING BRAND SECTION */}
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6">
                  <Cpu size={22} className="text-indigo-400 group-hover:text-white" />
                </div>
                <div className="flex flex-col">
                  <span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span>
                  <div className="flex items-center gap-1 mt-1">
                    <span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span>
                    <span className="text-[11px] font-black text-slate-400 leading-none">PRO</span>
                  </div>
                </div>
              </div>

              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                    <input 
                      type="text" 
                      value={studyName}
                      onChange={(e) => setStudyName(e.target.value)}
                      placeholder="Untitled Analysis"
                      className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate"
                    />
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">
                   {currentStudyId ? "System Repository" : "Temporary Workspace"}
                 </p>
              </div>
            </div>

            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button
                  onClick={() => setShowSODReference(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <BookOpen size={16} />
                  S/O/D Guide
                </button>
                <button
                  onClick={() => setShowDecisionLogic(true)}
                  className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"
                >
                  <GitBranch size={16} />
                  Logic Tree
                </button>
              </div>

              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">
                {justSaved ? (
                  <span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>
                ) : (
                   <span className="text-slate-300">{results ? 'Local draft' : ''}</span>
                )}
              </div>

              <div className="flex items-center gap-2">
                <button
                  onClick={handleUndo}
                  disabled={history.length === 0}
                  className={`p-2.5 rounded-xl transition-all ${
                    history.length > 0 
                      ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' 
                      : 'text-slate-200 cursor-not-allowed'
                  }`}
                  title="Undo last action"
                >
                  <Undo2 size={20} />
                </button>

                <button
                  onClick={handleSaveStudy}
                  disabled={!results && !contextText}
                  className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl
                    ${justSaved 
                      ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'
                    }
                    ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}
                  `}
                >
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">
                  Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.
                </p>
              </div>
            )}

            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button
                  onClick={() => setActiveTab('manual')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'manual' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Type size={14} />
                  Manual Synthesis
                </button>
                <button
                  onClick={() => setActiveTab('upload')}
                  className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${
                    activeTab === 'upload' 
                      ? 'border-indigo-600 text-indigo-600' 
                      : 'border-transparent text-slate-400 hover:text-slate-600'
                  }`}
                >
                  <Upload size={14} />
                  Knowledge Upload
                </button>
              </div>

              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center">
                      <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">
                        Operational Context Description
                      </label>
                      <button 
                        onClick={() => setShowContextBuilder(true)}
                        className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"
                      >
                        {/* Animated Gradient Background */}
                        <div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div>

                        {/* Shiny Overlay */}
                        <div className="absolute inset-0 opacity-0 group-hover:opacity-20 bg-gradient-to-tr from-white to-transparent transition-opacity duration-300"></div>

                        <div className="relative flex items-center gap-2">
                           <div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md">
                              <Sparkles size={16} className="text-white fill-white animate-pulse" />
                           </div>
                           <span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span>
                        </div>
                      </button>
                    </div>
                    <textarea
                      className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner"
                      placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..."
                      value={contextText}
                      onChange={(e) => setContextText(e.target.value)}
                    />
                  </div>
                )}

                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group">
                        <input 
                          type="file" 
                          id="file-upload"
                          className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                          accept=".txt,.pdf,.png,.jpg,.jpeg"
                          onChange={handleFileUpload}
                        />
                        {!fileData ? (
                          <>
                            <div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500">
                              <Upload size={28} />
                            </div>
                            <p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p>
                            <p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p>
                          </>
                        ) : (
                          <div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95">
                            <div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner">
                              <FileCheck size={28} />
                            </div>
                            <div className="flex-1 min-w-0">
                              <p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p>
                              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p>
                            </div>
                            <button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all">
                              <Trash2 size={20} />
                            </button>
                          </div>
                        )}
                     </div>
                  </div>
                )}

                {error && (
                  <div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500">
                    <AlertTriangle size={18} />
                    {error}
                  </div>
                )}

                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">
                  {results && results.length > 0 && (
                    <label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all">
                      <input 
                        type="checkbox" 
                        checked={isMerging} 
                        onChange={(e) => setIsMerging(e.target.checked)}
                        className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500"
                      />
                      <span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span>
                    </label>
                  )}
                  <button
                    onClick={handleGenerate}
                    disabled={isLoading}
                    className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}
                  >
                    {isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}
                    {isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}
                  </button>
                </div>
              </div>
            </div>

            {results && (
              <AnalysisResult 
                data={results} 
                onUpdate={handleResultsUpdate}
                onUndo={handleUndo}
                canUndo={history.length > 0}
              />
            )}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

