      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "An exhaustive technical physical description (minimum 5-8 sentences). Detail metallurgy, construction, internal architecture, and engineering interfaces. DO NOT use double quotes or mention images." 
          },
          location: { type: Type.STRING, description: "Where it is typically found on the asset." },
          visualCues: { type: Type.STRING, description: "What to look for (colors, shapes, textures) to identify it." }
