                      <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                      <td className="px-6 py-4 align-top group/interval">
                        <div className="font-medium text-xs leading-tight">{item.maintenanceTask}</div>
                        <button 
                          onClick={() => setOptimizingItem(item)}
                          className="text-[10px] text-slate-400 font-mono mt-1 hover:text-indigo-600 hover:bg-indigo-50 px-1.5 py-0.5 rounded transition-all flex items-center gap-1 group-hover/interval:border group-hover/interval:border-indigo-100"
                        >
                          <Target size={10} className="opacity-0 group-hover/interval:opacity-100" />
                          {item.interval}
                        </button>
                      </td>
                      <td className="px-6 py-4 align-middle text-center">
                         {isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}
                      </td>
                      <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 1 minute)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        handleSaveStudy(true);
      }
    }, 60000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      if (!isAutoSave) {
        setJustSaved(true);
        setTimeout(() => setJustSaved(false), 2000);
      }
    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar studies={savedStudies} currentStudyId={currentStudyId} onSelect={handleLoadStudy} onDelete={handleDeleteStudy} onNew={handleNewStudy} />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2"><input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" /></div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu, ChevronRight,
  Clock
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className="flex-1 text-[13px] font-medium leading-relaxed">{cleanLine.replace(/^[*|-]\s*/, '')}</span>
            </div>
          );
        }

        if (idx === 0 && role === 'model' && cleanLine.length < 50 && !cleanLine.endsWith('.')) {
          return (
            <h4 key={idx} className="font-black text-[11px] uppercase tracking-widest text-indigo-600 mb-2 border-b border-slate-100 pb-1">
              {cleanLine}
            </h4>
          );
        }

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{cleanLine}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const prompt = `
        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER REQUEST: ${userMsg}

        STRICT INSTRUCTIONS FOR MIRA:
        1. Action Requirement: If the user asks to add or change something, you MUST provide a JSON block inside <ACTION></ACTION> tags.
        2. Format: Act as a Senior Reliability Engineer. Use plain text for explanation and valid JSON for actions.
        3. Logic: All added items MUST follow the table's structural logic exactly.
        4. JSON Schema for 'ADD' items:
           {
             "type": "ADD",
             "item": {
                "component": "Specific Technical Name (e.g. 'Upper Thrust Bearing')",
                "componentIntel": {
                   "description": "Technical specs (2 sentences max).",
                   "location": "Specific asset coordinates.",
                   "visualCues": "Physical identifiers."
                },
                "function": "Primary design goal.",
                "functionalFailure": "Failure to perform.",
                "failureMode": "[Mechanism] due to [Cause]",
                "failureEffect": "Operational/Safety impact.",
                "consequenceCategory": "One of: Hidden - Safety/Env, Hidden - Operational, Evident - Safety/Env, Evident - Operational, Evident - Non-Operational",
                "iso14224Code": "ISO code (e.g. 'Wear')",
                "criticality": "High, Medium, or Low",
                "severity": 1-10,
                "occurrence": 1-10,
                "detection": 1-10,
                "maintenanceTask": "Specific action name",
                "interval": "Standard frequency (e.g. 'Monthly')",
                "taskType": "One of: Condition Monitoring, Time-Based, Run-to-Failure, Redesign, Failure Finding, Lubrication, Servicing, Restoration, Replacement"
             },
             "reason": "Engineering justification"
           }
        5. DO NOT use double quotes in descriptions or meta fields.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You strictly adhere to industrial RCM/FMECA schemas. You never use double quotes in your technical strings."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Directives synthesized.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA encountered a logic synchronization error." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 3;

      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Auxiliary Component',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via AI intelligence',
          location: proposal.item.componentIntel?.location || 'Refer to asset diagram',
          visualCues: proposal.item.componentIntel?.visualCues || 'Standard industrial cues'
        },
        function: proposal.item.function || 'General Function',
        functionalFailure: proposal.item.functionalFailure || 'Total loss of function',
        failureMode: proposal.item.failureMode || 'General wear',
        failureEffect: proposal.item.failureEffect || 'Local system impact',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'General Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity);
          updated.occurrence = Number(updated.occurrence);
          updated.detection = Number(updated.detection);
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;
    const unapplied = message.proposals.filter(p => !p.applied);
    unapplied.forEach(p => applySingleAction(p.id, messageIndex));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Technical Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Apply All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[1.5rem] p-4 shadow-sm transition-all border-l-[8px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[11px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'Proposed Item'}
                        </span>
                      </div>

                      <div className="space-y-2">
                        <div className="text-[11px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-2 rounded-xl border border-slate-100 italic">
                          {p.item?.failureMode || 'No description provided'}
                        </div>

                        {!p.applied && (
                          <div className="flex flex-wrap items-center gap-3 pt-2 border-t border-slate-100 mt-1">
                            {p.item?.maintenanceTask && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Wrench size={10} /> {p.item.maintenanceTask}
                               </div>
                            )}
                            {p.item?.interval && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Clock size={10} /> {p.item.interval}
                               </div>
                            )}
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg active:scale-95"
                     >
                       <Plus size={18} />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[650px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-6 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none">
                <Cpu size={80} className="rotate-12" />
            </div>

            <div className="flex items-center gap-4 relative z-10">
              <div className="p-2 bg-indigo-500/10 rounded-[1.2rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl tracking-tighter leading-none uppercase">MIRA</h3>
                    <span className="text-[8px] px-1.5 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest opacity-80 uppercase">Co-pilot</span>
                </div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Reliability Intelligence Assistant</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all active:scale-95"><ChevronDown size={28} /></button>
          </div>

          <div ref={scrollRef} onScroll={handleScroll} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[1.8rem] flex items-center justify-center shadow-2xl -rotate-3 border border-indigo-50 ring-4 ring-indigo-50/30"><Layers size={36} className="opacity-80" /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase">Consult MIRA</p>
                  <p className="text-[13px] text-slate-500 font-medium italic px-6">Ask me to add components, adjust risks, or refine your strategy based on SAE standards.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg leading-relaxed relative ${m.role === 'user' ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px] shadow-slate-200' : 'bg-white text-slate-800 border-2 border-indigo-50 rounded-bl-none shadow-indigo-100/10'}`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>
                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border-2 border-indigo-50 p-5 rounded-[2rem] rounded-bl-none shadow-lg flex items-center gap-4">
                  <div className="flex gap-1.5">
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Thinking...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button onClick={handleReset} className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[1.5rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 shadow-inner"><RotateCcw size={20} /></button>
              <div className="flex-1 relative">
                <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder="Request directives..." className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner" />
              </div>
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-4 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 disabled:opacity-30 transition-all shadow-xl shadow-indigo-200 flex items-center justify-center"><Send size={20} /></button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-[0_15px_40px_rgba(79,70,229,0.3)] transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={28} /> : <Bot size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 border-2 border-white rounded-lg flex items-center justify-center shadow-lg">
            <Sparkles size={10} className="text-white fill-white" />
          </div>
        )}
      </button>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      if (resultsRef.current && resultsRef.current.length > 0) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }
      if (!isAutoSave) {
        setJustSaved(true);
        setTimeout(() => setJustSaved(false), 2000);
      }
    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar studies={savedStudies} currentStudyId={currentStudyId} onSelect={handleLoadStudy} onDelete={handleDeleteStudy} onNew={handleNewStudy} />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2"><input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" /></div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-50 text-emerald-600 border border-emerald-200 shadow-emerald-50' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu, ChevronRight,
  Clock
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className="flex-1 text-[13px] font-medium leading-relaxed">{cleanLine.replace(/^[*|-]\s*/, '')}</span>
            </div>
          );
        }

        if (idx === 0 && role === 'model' && cleanLine.length < 50 && !cleanLine.endsWith('.')) {
          return (
            <h4 key={idx} className="font-black text-[11px] uppercase tracking-widest text-indigo-600 mb-2 border-b border-slate-100 pb-1">
              {cleanLine}
            </h4>
          );
        }

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{cleanLine}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const prompt = `
        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER REQUEST: ${userMsg}

        STRICT INSTRUCTIONS FOR MIRA:
        1. Action Requirement: If the user asks to add or change something, you MUST provide a JSON block inside <ACTION></ACTION> tags.
        2. Component Naming: You MUST provide a specific, professional technical name for any component added (e.g., 'Primary Discharge Impeller' instead of just 'Impeller').
        3. Format: Act as a Senior Reliability Engineer. Use plain text for explanation and valid JSON for actions.
        4. Logic: All added items MUST follow the table's structural logic exactly.
        5. Required Metadata: For 'ADD' items, you MUST populate 'componentIntel' with a physical description, location, and visual cues.

        JSON Schema for 'ADD' items:
           {
             "type": "ADD",
             "item": {
                "component": "Specific Technical Name",
                "componentIntel": {
                   "description": "Technical specs (metallurgy, construction, 2 sentences max).",
                   "location": "Specific asset coordinates.",
                   "visualCues": "Physical identifiers."
                },
                "function": "Primary design goal.",
                "functionalFailure": "Failure to perform.",
                "failureMode": "[Mechanism] due to [Cause]",
                "failureEffect": "Operational/Safety impact.",
                "consequenceCategory": "One of: Hidden - Safety/Env, Hidden - Operational, Evident - Safety/Env, Evident - Operational, Evident - Non-Operational",
                "iso14224Code": "ISO code (e.g. 'Wear')",
                "criticality": "High, Medium, or Low",
                "severity": 1-10,
                "occurrence": 1-10,
                "detection": 1-10,
                "maintenanceTask": "Specific action name",
                "interval": "Standard frequency (e.g. 'Monthly')",
                "taskType": "One of: Condition Monitoring, Time-Based, Run-to-Failure, Redesign, Failure Finding, Lubrication, Servicing, Restoration, Replacement"
             },
             "reason": "Engineering justification"
           }
        6. DO NOT use double quotes in descriptions or meta fields.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You strictly adhere to industrial RCM/FMECA schemas. You provide high-fidelity technical data for every column in the table. You never use double quotes in your technical strings."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Directives synthesized.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA encountered a logic synchronization error." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 3;

      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Auxiliary Component',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via MIRA Intelligence synthesis.',
          location: proposal.item.componentIntel?.location || 'Refer to asset structural diagram.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Standard industrial physical cues.'
        },
        function: proposal.item.function || 'General design function.',
        functionalFailure: proposal.item.functionalFailure || 'Total loss of operational function.',
        failureMode: proposal.item.failureMode || 'General wear and degradation.',
        failureEffect: proposal.item.failureEffect || 'Local system operational impact.',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'Visual Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity);
          updated.occurrence = Number(updated.occurrence);
          updated.detection = Number(updated.detection);
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;
    const unapplied = message.proposals.filter(p => !p.applied);
    unapplied.forEach(p => applySingleAction(p.id, messageIndex));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Technical Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Apply All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[1.5rem] p-4 shadow-sm transition-all border-l-[8px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[11px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'Unspecified Component'}
                        </span>
                      </div>

                      <div className="space-y-2">
                        <div className="text-[11px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-2 rounded-xl border border-slate-100 italic">
                          {p.item?.failureMode || 'No mode description provided'}
                        </div>

                        {!p.applied && (
                          <div className="flex flex-wrap items-center gap-3 pt-2 border-t border-slate-100 mt-1">
                            {p.item?.maintenanceTask && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Wrench size={10} /> {p.item.maintenanceTask}
                               </div>
                            )}
                            {p.item?.interval && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Clock size={10} /> {p.item.interval}
                               </div>
                            )}
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg active:scale-95"
                     >
                       <Plus size={18} />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[650px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-6 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none">
                <Cpu size={80} className="rotate-12" />
            </div>

            <div className="flex items-center gap-4 relative z-10">
              <div className="p-2 bg-indigo-500/10 rounded-[1.2rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl tracking-tighter leading-none uppercase">MIRA</h3>
                    <span className="text-[8px] px-1.5 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest opacity-80 uppercase">Co-pilot</span>
                </div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Reliability Intelligence Assistant</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all active:scale-95"><ChevronDown size={28} /></button>
          </div>

          <div ref={scrollRef} onScroll={handleScroll} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[1.8rem] flex items-center justify-center shadow-2xl -rotate-3 border border-indigo-50 ring-4 ring-indigo-50/30"><Layers size={36} className="opacity-80" /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase">Consult MIRA</p>
                  <p className="text-[13px] text-slate-500 font-medium italic px-6">Ask me to add components, adjust risks, or refine your strategy based on SAE standards.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg leading-relaxed relative ${m.role === 'user' ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px] shadow-slate-200' : 'bg-white text-slate-800 border-2 border-indigo-50 rounded-bl-none shadow-indigo-100/10'}`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>
                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border-2 border-indigo-50 p-5 rounded-[2rem] rounded-bl-none shadow-lg flex items-center gap-4">
                  <div className="flex gap-1.5">
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Thinking...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button onClick={handleReset} className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[1.5rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 shadow-inner"><RotateCcw size={20} /></button>
              <div className="flex-1 relative">
                <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder="Request directives..." className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner" />
              </div>
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-4 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 disabled:opacity-30 transition-all shadow-xl shadow-indigo-200 flex items-center justify-center"><Send size={20} /></button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-[0_15px_40px_rgba(79,70,229,0.3)] transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={28} /> : <Bot size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 border-2 border-white rounded-lg flex items-center justify-center shadow-lg">
            <Sparkles size={10} className="text-white fill-white" />
          </div>
        )}
      </button>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const studies = await getAllStudies();
        setSavedStudies(studies);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type,
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar studies={savedStudies} currentStudyId={currentStudyId} onSelect={handleLoadStudy} onDelete={handleDeleteStudy} onNew={handleNewStudy} />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2"><input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" /></div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-w-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  MessageSquare, X, Send, Bot, Sparkles, ChevronDown, 
  Plus, Check, ListChecks, CheckCircle2,
  AlertTriangle, Wrench, Layers, Info, Tag, RotateCcw, Cpu, ChevronRight,
  Clock
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model' }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className="flex-1 text-[13px] font-medium leading-relaxed">{cleanLine.replace(/^[*|-]\s*/, '')}</span>
            </div>
          );
        }

        if (idx === 0 && role === 'model' && cleanLine.length < 50 && !cleanLine.endsWith('.')) {
          return (
            <h4 key={idx} className="font-black text-[11px] uppercase tracking-widest text-indigo-600 mb-2 border-b border-slate-100 pb-1">
              {cleanLine}
            </h4>
          );
        }

        return <p key={idx} className="leading-relaxed text-[13px] font-medium">{cleanLine}</p>;
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);
  const chatScrollPos = useRef<number>(0);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      if (chatScrollPos.current > 0) {
        scrollRef.current.scrollTop = chatScrollPos.current;
      } else {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [isOpen]);

  const handleScroll = () => {
    if (scrollRef.current) {
      chatScrollPos.current = scrollRef.current.scrollTop;
    }
  };

  useEffect(() => {
    if (isOpen && scrollRef.current && messages.length > 0) {
      const lastMsg = messages[messages.length - 1];
      if (lastMsg.role === 'user') {
        scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
      }
    }
  }, [messages, isOpen]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object' && (a.item || a.type === 'DELETE')) {
            proposals.push({
              ...a,
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              applied: false,
              item: a.item || {} 
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse AI action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleReset = () => {
    setMessages([]);
    chatScrollPos.current = 0;
    setInput('');
    setIsLoading(false);
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const safeData = (data || []).filter(item => !!item);

      const contextSummary = safeData.slice(-20).map(i => ({
        id: i.id,
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        iso: i.iso14224Code
      }));

      const prompt = `
        RCM DATA CONTEXT: ${JSON.stringify(contextSummary)}
        USER REQUEST: ${userMsg}

        STRICT INSTRUCTIONS FOR MIRA:
        1. Action Requirement: If the user asks to add or change something, you MUST provide a JSON block inside <ACTION></ACTION> tags.
        2. Component Naming: You MUST provide a specific, professional technical name for any component added (e.g., 'Primary Discharge Impeller' instead of just 'Impeller').
        3. Format: Act as a Senior Reliability Engineer. Use plain text for explanation and valid JSON for actions.
        4. Logic: All added items MUST follow the table's structural logic exactly.
        5. Required Metadata: For 'ADD' items, you MUST populate 'componentIntel' with a physical description, location, and visual cues.

        JSON Schema for 'ADD' items:
           {
             "type": "ADD",
             "item": {
                "component": "Specific Technical Name",
                "componentIntel": {
                   "description": "Technical specs (metallurgy, construction, 2 sentences max).",
                   "location": "Specific asset coordinates.",
                   "visualCues": "Physical identifiers."
                },
                "function": "Primary design goal.",
                "functionalFailure": "Failure to perform.",
                "failureMode": "[Mechanism] due to [Cause]",
                "failureEffect": "Operational/Safety impact.",
                "consequenceCategory": "One of: Hidden - Safety/Env, Hidden - Operational, Evident - Safety/Env, Evident - Operational, Evident - Non-Operational",
                "iso14224Code": "ISO code (e.g. 'Wear')",
                "criticality": "High, Medium, or Low",
                "severity": 1-10,
                "occurrence": 1-10,
                "detection": 1-10,
                "maintenanceTask": "Specific action name",
                "interval": "Standard frequency (e.g. 'Monthly')",
                "taskType": "One of: Condition Monitoring, Time-Based, Run-to-Failure, Redesign, Failure Finding, Lubrication, Servicing, Restoration, Replacement"
             },
             "reason": "Engineering justification"
           }
        6. DO NOT use double quotes in descriptions or meta fields.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: "You are MIRA, a world-class RCM specialist. You strictly adhere to industrial RCM/FMECA schemas. You provide high-fidelity technical data for every column in the table. You never use double quotes in your technical strings."
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Directives synthesized.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "MIRA encountered a logic synchronization error." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 3;

      const newItem: RCMItem = {
        id: `rcm-ai-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Auxiliary Component',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via MIRA Intelligence synthesis.',
          location: proposal.item.componentIntel?.location || 'Refer to asset structural diagram.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Standard industrial physical cues.'
        },
        function: proposal.item.function || 'General design function.',
        functionalFailure: proposal.item.functionalFailure || 'Total loss of operational function.',
        failureMode: proposal.item.failureMode || 'General wear and degradation.',
        failureEffect: proposal.item.failureEffect || 'Local system operational impact.',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality as any || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'Visual Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : item.component === proposal.item?.component;
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity);
          updated.occurrence = Number(updated.occurrence);
          updated.detection = Number(updated.detection);
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    } 
    else if (proposal.type === 'DELETE' && proposal.item.id) {
      newData = newData.filter(item => item && item.id !== proposal.item.id);
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  const applyAllActions = (messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;
    const unapplied = message.proposals.filter(p => !p.applied);
    unapplied.forEach(p => applySingleAction(p.id, messageIndex));
  };

  const renderProposalsSection = (message: Message, messageIndex: number) => {
    if (!message.proposals || message.proposals.length === 0) return null;
    const unappliedCount = message.proposals.filter(p => !p.applied).length;

    return (
      <div className="mt-4 w-full space-y-3 animate-in fade-in slide-in-from-bottom-2 duration-300">
        <div className="flex items-center justify-between px-2 mb-2">
          <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] flex items-center gap-2">
            <ListChecks size={14} className="text-indigo-400" /> Technical Directives
          </h5>
          {unappliedCount > 1 && (
            <button 
              onClick={() => applyAllActions(messageIndex)}
              className="text-[9px] font-black text-indigo-600 bg-indigo-50 px-3 py-1.5 rounded-xl hover:bg-indigo-100 transition-all flex items-center gap-1.5 border border-indigo-100 shadow-sm uppercase tracking-tighter"
            >
              <CheckCircle2 size={12} /> Apply All
            </button>
          )}
        </div>

        <div className="space-y-3 max-h-[350px] overflow-y-auto custom-scrollbar pr-1">
          {message.proposals.map((p) => {
            if (!p) return null;
            return (
              <div 
                key={p.id} 
                className={`bg-white border rounded-[1.5rem] p-4 shadow-sm transition-all border-l-[8px] ${
                  p.applied ? 'border-emerald-500 bg-emerald-50/20' : 
                  p.type === 'ADD' ? 'border-indigo-600' : 
                  p.type === 'UPDATE' ? 'border-amber-500' : 'border-red-500'
                }`}
              >
                <div className="flex justify-between items-start gap-3">
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-2">
                        <span className={`text-[8px] font-black uppercase tracking-widest px-1.5 py-0.5 rounded-full ${
                          p.applied ? 'bg-emerald-500 text-white' : 
                          p.type === 'ADD' ? 'bg-indigo-600 text-white' : 
                          p.type === 'UPDATE' ? 'bg-amber-100 text-amber-700' : 'bg-red-100 text-red-700'
                        }`}>
                          {p.applied ? 'COMMITTED' : p.type}
                        </span>
                        <span className="text-[11px] font-black text-slate-900 truncate block uppercase tracking-tight">
                          {p.item?.component || 'Unspecified Component'}
                        </span>
                      </div>

                      <div className="space-y-2">
                        <div className="text-[11px] font-semibold text-slate-600 leading-snug bg-slate-50/50 p-2 rounded-xl border border-slate-100 italic">
                          {p.item?.failureMode || 'No mode description provided'}
                        </div>

                        {!p.applied && (
                          <div className="flex flex-wrap items-center gap-3 pt-2 border-t border-slate-100 mt-1">
                            {p.item?.maintenanceTask && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Wrench size={10} /> {p.item.maintenanceTask}
                               </div>
                            )}
                            {p.item?.interval && (
                               <div className="flex items-center gap-1.5 text-[9px] font-black text-slate-400">
                                 <Clock size={10} /> {p.item.interval}
                               </div>
                            )}
                          </div>
                        )}
                      </div>
                   </div>

                   {!p.applied && (
                     <button 
                       onClick={() => applySingleAction(p.id, messageIndex)}
                       className="p-2 bg-slate-900 text-white rounded-xl hover:bg-indigo-600 transition-all shrink-0 shadow-lg active:scale-95"
                     >
                       <Plus size={18} />
                     </button>
                   )}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[650px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-gradient-to-br from-slate-900 via-slate-800 to-indigo-950 p-6 text-white flex justify-between items-center shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-5 pointer-events-none">
                <Cpu size={80} className="rotate-12" />
            </div>

            <div className="flex items-center gap-4 relative z-10">
              <div className="p-2 bg-indigo-500/10 rounded-[1.2rem] border border-indigo-400/30 shadow-inner backdrop-blur-md">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <div className="flex items-center gap-2">
                    <h3 className="font-black text-xl tracking-tighter leading-none uppercase">MIRA</h3>
                    <span className="text-[8px] px-1.5 py-0.5 bg-indigo-600 rounded-md font-black tracking-widest opacity-80 uppercase">Co-pilot</span>
                </div>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Reliability Intelligence Assistant</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all active:scale-95"><ChevronDown size={28} /></button>
          </div>

          <div ref={scrollRef} onScroll={handleScroll} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[1.8rem] flex items-center justify-center shadow-2xl -rotate-3 border border-indigo-50 ring-4 ring-indigo-50/30"><Layers size={36} className="opacity-80" /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase">Consult MIRA</p>
                  <p className="text-[13px] text-slate-500 font-medium italic px-6">Ask me to add components, adjust risks, or refine your strategy based on SAE standards.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg leading-relaxed relative ${m.role === 'user' ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px] shadow-slate-200' : 'bg-white text-slate-800 border-2 border-indigo-50 rounded-bl-none shadow-indigo-100/10'}`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>
                {renderProposalsSection(m, i)}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border-2 border-indigo-50 p-5 rounded-[2rem] rounded-bl-none shadow-lg flex items-center gap-4">
                  <div className="flex gap-1.5">
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                    <div className="w-2.5 h-2.5 bg-indigo-600 rounded-full animate-bounce"></div>
                  </div>
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Thinking...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button onClick={handleReset} className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-[1.5rem] transition-all border border-slate-100 flex items-center justify-center shrink-0 shadow-inner"><RotateCcw size={20} /></button>
              <div className="flex-1 relative">
                <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder="Request directives..." className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 font-bold shadow-inner" />
              </div>
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-4 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 disabled:opacity-30 transition-all shadow-xl shadow-indigo-200 flex items-center justify-center"><Send size={20} /></button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-[0_15px_40px_rgba(79,70,229,0.3)] transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={28} /> : <Bot size={28} />}
        {!isOpen && (
          <div className="absolute -top-1 -right-1 w-6 h-6 bg-emerald-500 border-2 border-white rounded-lg flex items-center justify-center shadow-lg">
            <Sparkles size={10} className="text-white fill-white" />
          </div>
        )}
      </button>
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { RCMItem, FileData, InspectionSheet, ComponentIntel } from "../types";

// Define the expected output schema for structured JSON
const rcmSchema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      component: { 
        type: Type.STRING, 
        description: "Standard component name at Level 3/4 (e.g., 'Main Shaft', 'Mechanical Seal', 'Bearing Housing', 'Drive Motor')." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "A concise technical physical description (2-3 sentences). Detail metallurgy and construction. DO NOT use double quotes or mention images." 
          },
          location: { type: Type.STRING, description: "Where it is typically found on the asset." },
          visualCues: { type: Type.STRING, description: "What to look for (colors, shapes, textures) to identify it." }
        },
        required: ["description", "location", "visualCues"]
      },
      function: { 
        type: Type.STRING,
        description: "The primary function of the component."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "How the component fails to fulfill its function."
      },
      failureMode: { 
        type: Type.STRING,
        description: "Strictly: [Mechanism] due to [Cause]. Example: 'Erosion due to abrasive slurry' or 'Seizure due to loss of lubrication'."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "The immediate impact on safety, environment, and operations."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ],
        description: "SAE JA1011 Consequence classification."
      },
      iso14224Code: {
        type: Type.STRING,
        description: "Standard failure code (e.g., Wear, Corrosion, Fatigue, Overheating, Leakage, Breakage)."
      },
      criticality: { 
        type: Type.STRING, 
        enum: ["High", "Medium", "Low"],
        description: "Qualitative priority."
      },
      severity: {
        type: Type.INTEGER,
        description: "Severity (1-10). If safety is compromised, score 9-10. Major production loss is 8+."
      },
      occurrence: {
        type: Type.INTEGER,
