import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId // Preserve folder association
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // First, un-group studies associated with this folder
      const studiesToUpdate = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToUpdate) {
        await saveStudyToDB({ ...study, folderId: undefined });
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedStudy = JSON.parse(content) as SavedStudy;

        // Ensure standard properties exist before saving
        if (!importedStudy.name || !importedStudy.items) {
          throw new Error("Invalid study format");
        }

        // Generate a new ID if needed or prefix with "imported"
        const finalStudy: SavedStudy = {
          ...importedStudy,
          id: `imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          timestamp: Date.now(),
          folderId: undefined // Don't preserve folder ID from other systems
        };

        await saveStudyToDB(finalStudy);
        const freshStudies = await getAllStudies();
        setSavedStudies(freshStudies);
        handleLoadStudy(finalStudy);

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import study. Ensure the file is a valid RCM Pro JSON.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onImport={handleImportStudy}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2"><input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" /></div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? "Synthesizing Document..." : "Extract & Structure Context"}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

export interface InspectionStep {
  step: number;
  description: string;
  criteria: string;
  technique: string;
}

export interface InspectionSheet {
  responsibility: string;
  estimatedTime: string;
  safetyPrecautions: string;
  toolsRequired: string;
  steps: InspectionStep[];

  checkPointDescription?: string;
  type?: 'Qualitative' | 'Quantitative';
  criteriaLimits?: string; 
  normalCondition?: string; 
}

export interface ComponentIntel {
  description: string;
  location: string;
  visualCues: string;
}

export type ConsequenceCategory = 
  | 'Hidden - Safety/Env' 
  | 'Hidden - Operational' 
  | 'Evident - Safety/Env' 
  | 'Evident - Operational'
  | 'Evident - Non-Operational';

export interface RCMItem {
  id: string;
  component: string;
  function: string;
  functionalFailure: string;
  failureMode: string;
  failureEffect: string;
  criticality: 'High' | 'Medium' | 'Low';

  consequenceCategory: ConsequenceCategory;
  iso14224Code: string;

  severity: number;
  occurrence: number;
  detection: number;
  rpn: number;

  maintenanceTask: string;
  interval: string;
  pfInterval?: string; // New field for reliability optimization
  taskType: 'Condition Monitoring' | 'Time-Based' | 'Run-to-Failure' | 'Redesign' | 'Failure Finding' | 'Lubrication' | 'Servicing' | 'Restoration' | 'Replacement';
  inspectionSheet?: InspectionSheet;
  componentIntel?: ComponentIntel;
  isNew?: boolean;
}

export interface AnalysisStats {
  totalItems: number;
  highRisk: number;
  mediumRisk: number;
  lowRisk: number;
}

export type InputMode = 'manual' | 'upload';

export interface FileData {
  name: string;
  mimeType: string;
  data: string;
}

export interface Folder {
  id: string;
  name: string;
  timestamp: number;
}

export interface SavedStudy {
  id: string;
  name: string;
  timestamp: number;
  items: RCMItem[];
  contextText: string;
  fileName?: string;
  folderId?: string;
  isFinished?: boolean;
}

import React, { useState, useRef } from 'react';
import { SavedStudy, Folder } from '../types';
import { Plus, Trash2, FileText, Calendar, Database, FolderOpen, AlertCircle, FolderPlus, ChevronRight, ChevronDown, Move, Download, Upload, CheckCircle2 } from 'lucide-react';

interface SidebarProps {
  studies: SavedStudy[];
  folders: Folder[];
  currentStudyId: string | null;
  onSelect: (study: SavedStudy) => void;
  onDelete: (id: string) => void;
  onNew: () => void;
  onNewFolder: (name: string) => void;
  onDeleteFolder: (id: string) => void;
  onMoveStudy: (studyId: string, folderId?: string) => void;
  onExport: (study: SavedStudy) => void;
  onImport: (file: File) => void;
  onToggleFinished: (studyId: string) => void;
  className?: string;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  studies, 
  folders,
  currentStudyId, 
  onSelect, 
  onDelete, 
  onNew,
  onNewFolder,
  onDeleteFolder,
  onMoveStudy,
  onExport,
  onImport,
  onToggleFinished,
  className = "" 
}) => {
  const [deleteConfirm, setDeleteConfirm] = useState<{ type: 'study' | 'folder', id: string } | null>(null);
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(folders.map(f => f.id)));
  const [showMoveMenu, setShowMoveMenu] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleFolder = (id: string) => {
    const next = new Set(expandedFolders);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setExpandedFolders(next);
  };

  const handleCreateFolder = () => {
    const name = prompt("Enter folder name:");
    if (name) onNewFolder(name);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onImport(file);
      e.target.value = '';
    }
  };

  const renderStudyItem = (study: SavedStudy) => (
    <div
      key={study.id}
      onClick={() => {
        setDeleteConfirm(null);
        onSelect(study);
      }}
      className={`group flex items-start gap-3 p-3 rounded-lg cursor-pointer border transition-all duration-200 relative select-none mb-2
        ${currentStudyId === study.id 
          ? 'bg-white border-indigo-200 shadow-md ring-1 ring-indigo-50' 
          : 'bg-white border-transparent hover:bg-slate-100/80 hover:border-slate-200'
        }`}
    >
      <div className="flex flex-col items-center shrink-0 gap-2">
        <div className={`mt-0.5 p-2 rounded-lg transition-colors ${currentStudyId === study.id ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-400 group-hover:bg-white'}`}>
          <FileText size={18} />
        </div>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onToggleFinished(study.id);
          }}
          className={`transition-all duration-300 ${study.isFinished ? 'text-emerald-500 scale-110' : 'text-slate-200 hover:text-slate-400'}`}
          title={study.isFinished ? "Study Finished" : "Mark as Finished"}
        >
          <CheckCircle2 size={16} fill={study.isFinished ? "currentColor" : "none"} strokeWidth={study.isFinished ? 3 : 2} className={study.isFinished ? "fill-emerald-500/20" : ""} />
        </button>
      </div>

      <div className="flex-1 min-w-0 pr-6">
        <h3 className={`text-sm font-semibold truncate transition-colors ${currentStudyId === study.id ? 'text-indigo-900' : 'text-slate-700'} ${study.isFinished ? 'opacity-70' : ''}`}>
          {study.name}
        </h3>
        <div className="flex items-center gap-2 mt-1.5">
          <span className="flex items-center gap-1 text-[10px] text-slate-400 font-medium">
            <Calendar size={10} />
            {new Date(study.timestamp).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
          </span>
          <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded-full border border-slate-200">
            {study.items.length} Items
          </span>
        </div>
      </div>

      {/* Interaction Icons */}
      <div className="absolute right-2 top-2 flex gap-0.5 opacity-0 group-hover:opacity-100 transition-all">
        <button
          onClick={(e) => {
            e.stopPropagation();
            onExport(study);
          }}
          className="p-1.5 text-slate-300 hover:text-emerald-500 hover:bg-emerald-50 rounded-md"
          title="Export JSON"
        >
          <Download size={14} />
        </button>
        <button
          onClick={(e) => {
            e.stopPropagation();
            setShowMoveMenu(showMoveMenu === study.id ? null : study.id);
          }}
          className="p-1.5 text-slate-300 hover:text-indigo-500 hover:bg-indigo-50 rounded-md"
          title="Move to Folder"
        >
          <Move size={14} />
        </button>
        <button
          onClick={(e) => {
            e.stopPropagation();
            setDeleteConfirm({ type: 'study', id: study.id });
          }}
          className="p-1.5 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-md"
          title="Delete Study"
        >
          <Trash2 size={14} />
        </button>
      </div>

      {/* Move Menu Popover */}
      {showMoveMenu === study.id && (
        <div className="absolute right-0 top-10 bg-white border border-slate-200 rounded-xl shadow-2xl z-20 min-w-[160px] p-2 animate-in fade-in zoom-in-95" onClick={e => e.stopPropagation()}>
          <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2">Move to Folder</div>
          <button 
            onClick={() => { onMoveStudy(study.id); setShowMoveMenu(null); }}
            className="w-full text-left px-3 py-2 text-xs font-bold text-slate-600 hover:bg-slate-50 rounded-lg flex items-center gap-2"
          >
            <FolderOpen size={14} className="text-slate-400" /> Uncategorized
          </button>
          {folders.map(f => (
            <button 
              key={f.id}
              onClick={() => { onMoveStudy(study.id, f.id); setShowMoveMenu(null); }}
              className="w-full text-left px-3 py-2 text-xs font-bold text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 rounded-lg flex items-center gap-2"
            >
              <FolderPlus size={14} className="text-indigo-400" /> {f.name}
            </button>
          ))}
        </div>
      )}

      {/* Delete Confirmation Overlay */}
      {deleteConfirm?.type === 'study' && deleteConfirm.id === study.id && (
        <div className="absolute inset-0 bg-red-50/95 backdrop-blur-sm rounded-lg flex items-center justify-between px-3 animate-in fade-in duration-200 z-10">
           <span className="text-xs font-bold text-red-600 flex items-center gap-1">
             <AlertCircle size={12} /> Delete?
           </span>
           <div className="flex gap-2">
             <button onClick={(e) => { e.stopPropagation(); onDelete(study.id); setDeleteConfirm(null); }} className="text-xs bg-red-600 text-white px-2 py-1 rounded hover:bg-red-700 font-medium">Yes</button>
             <button onClick={(e) => { e.stopPropagation(); setDeleteConfirm(null); }} className="text-xs bg-white border border-red-200 text-red-600 px-2 py-1 rounded hover:bg-red-50 font-medium">No</button>
           </div>
        </div>
      )}
    </div>
  );

  return (
    <div className={`bg-white border-r border-slate-200 flex flex-col h-full ${className}`}>
      {/* Hidden Import Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept=".json" 
        className="hidden" 
      />

      {/* Sidebar Header */}
      <div className="p-4 border-b border-slate-200 space-y-3">
        <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
          <Database size={14} />
          Your Studies
        </h2>
        <div className="flex gap-2">
          <button
            onClick={onNew}
            className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2.5 px-4 rounded-xl text-sm font-medium transition-all shadow-md shadow-indigo-100 transform active:scale-95"
          >
            <Plus size={18} />
            New Study
          </button>
          <button
            onClick={handleImportClick}
            className="p-2.5 bg-slate-100 hover:bg-emerald-50 text-slate-600 hover:text-emerald-600 rounded-xl transition-all active:scale-95"
            title="Import Study JSON"
          >
            <Upload size={18} />
          </button>
          <button
            onClick={handleCreateFolder}
            className="p-2.5 bg-slate-100 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-xl transition-all active:scale-95"
            title="New Folder"
          >
            <FolderPlus size={18} />
          </button>
        </div>
      </div>

      {/* Folders and Studies List */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-3 bg-slate-50/50">
        {folders.length === 0 && studies.length === 0 ? (
          <div className="text-center py-12 px-4">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-100 text-slate-300 mb-4">
              <FolderOpen size={32} strokeWidth={1.5} />
            </div>
            <p className="text-sm text-slate-600 font-medium">No saved studies</p>
            <p className="text-xs text-slate-400 mt-2 leading-relaxed">
              Create a new RCM analysis, import a shared file, or add a folder.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {/* Folder Sections */}
            {folders.map(folder => {
              const folderStudies = studies.filter(s => s.folderId === folder.id);
              const isExpanded = expandedFolders.has(folder.id);

              return (
                <div key={folder.id} className="space-y-1">
                  <div className={`group flex items-center gap-2 p-2 rounded-xl transition-all cursor-pointer ${isExpanded ? 'bg-indigo-50/40' : 'hover:bg-white'}`}>
                    <button onClick={() => toggleFolder(folder.id)} className="p-1 text-slate-400 hover:text-indigo-600">
                      {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                    </button>
                    <div onClick={() => toggleFolder(folder.id)} className="flex-1 flex items-center gap-2">
                      <FolderPlus size={16} className={`${isExpanded ? 'text-indigo-600' : 'text-slate-400'}`} />
                      <span className={`text-xs font-black uppercase tracking-widest ${isExpanded ? 'text-indigo-700' : 'text-slate-500'}`}>{folder.name}</span>
                      <span className="text-[10px] bg-white px-1.5 py-0.5 rounded border border-slate-100 text-slate-400 font-bold">{folderStudies.length}</span>
                    </div>
                    <button 
                      onClick={(e) => { e.stopPropagation(); setDeleteConfirm({ type: 'folder', id: folder.id }); }}
                      className="p-1 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all"
                    >
                      <Trash2 size={12} />
                    </button>
                  </div>

                  {isExpanded && (
                    <div className="pl-4 border-l border-indigo-100/50 ml-4 animate-in slide-in-from-top-1 duration-200">
                      {folderStudies.length === 0 ? (
                        <div className="py-2 px-3 text-[10px] text-slate-300 italic font-medium">Empty Folder</div>
                      ) : (
                        folderStudies.map(renderStudyItem)
                      )}
                    </div>
                  )}

                  {/* Folder Delete Confirmation */}
                  {deleteConfirm?.type === 'folder' && deleteConfirm.id === folder.id && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 p-4">
                      <div className="bg-white p-6 rounded-3xl shadow-2xl border border-slate-100 max-w-sm w-full text-center">
                        <div className="w-12 h-12 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
                          <AlertCircle size={24} />
                        </div>
                        <h4 className="text-lg font-black text-slate-900 uppercase tracking-tighter mb-2">Delete Folder?</h4>
                        <p className="text-sm text-slate-500 mb-6">Studies inside will become <b>Uncategorized</b>. This action cannot be undone.</p>
                        <div className="flex gap-3">
                          <button onClick={() => { onDeleteFolder(folder.id); setDeleteConfirm(null); }} className="flex-1 py-3 bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-red-700 transition-all">Yes, Delete</button>
                          <button onClick={() => setDeleteConfirm(null)} className="flex-1 py-3 bg-slate-100 text-slate-600 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-200 transition-all">Cancel</button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}

            {/* Uncategorized Section */}
            <div>
              <div className="flex items-center gap-2 p-2 mb-2">
                <FolderOpen size={16} className="text-slate-300" />
                <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Uncategorized</span>
              </div>
              {studies.filter(s => !s.folderId).map(renderStudyItem)}
            </div>
          </div>
        )}
      </div>

      {/* Footer Info */}
      <div className="p-4 border-t border-slate-200 bg-slate-50 text-[10px] text-slate-400 text-center font-bold tracking-tight">
        Reliability Intelligence Repository
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId, // Preserve folder association
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // First, un-group studies associated with this folder
      const studiesToUpdate = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToUpdate) {
        await saveStudyToDB({ ...study, folderId: undefined });
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      // If we're currently viewing this study, update current state too
      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedStudy = JSON.parse(content) as SavedStudy;

        // Ensure standard properties exist before saving
        if (!importedStudy.name || !importedStudy.items) {
          throw new Error("Invalid study format");
        }

        // Generate a new ID if needed or prefix with "imported"
        const finalStudy: SavedStudy = {
          ...importedStudy,
          id: `imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          timestamp: Date.now(),
          folderId: undefined // Don't preserve folder ID from other systems
        };

        await saveStudyToDB(finalStudy);
        const freshStudies = await getAllStudies();
        setSavedStudies(freshStudies);
        handleLoadStudy(finalStudy);

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import study. Ensure the file is a valid RCM Pro JSON.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? "Synthesizing Document..." : "Extract & Structure Context"}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId, // Preserve folder association
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // First, un-group studies associated with this folder
      const studiesToUpdate = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToUpdate) {
        await saveStudyToDB({ ...study, folderId: undefined });
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      // If we're currently viewing this study, update current state too
      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedStudy = JSON.parse(content) as SavedStudy;

        // Ensure standard properties exist before saving
        if (!importedStudy.name || !importedStudy.items) {
          throw new Error("Invalid study format");
        }

        // Generate a new ID if needed or prefix with "imported"
        const finalStudy: SavedStudy = {
          ...importedStudy,
          id: `imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          timestamp: Date.now(),
          folderId: undefined // Don't preserve folder ID from other systems
        };

        await saveStudyToDB(finalStudy);
        const freshStudies = await getAllStudies();
        setSavedStudies(freshStudies);
        handleLoadStudy(finalStudy);

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import study. Ensure the file is a valid RCM Pro JSON.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? "Synthesizing Document..." : "Extract & Structure Context"}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 shadow-indigo-300 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useRef } from 'react';
import { SavedStudy, Folder } from '../types';
import { Plus, Trash2, FileText, Calendar, Database, FolderOpen, AlertCircle, FolderPlus, ChevronRight, ChevronDown, Move, Download, Upload, CheckCircle2 } from 'lucide-react';

interface SidebarProps {
  studies: SavedStudy[];
  folders: Folder[];
  currentStudyId: string | null;
  onSelect: (study: SavedStudy) => void;
  onDelete: (id: string) => void;
  onNew: () => void;
  onNewFolder: (name: string) => void;
  onDeleteFolder: (id: string) => void;
  onMoveStudy: (studyId: string, folderId?: string) => void;
  onExport: (study: SavedStudy) => void;
  onExportFolder: (folder: Folder) => void;
  onImport: (file: File) => void;
  onToggleFinished: (studyId: string) => void;
  className?: string;
}

export const Sidebar: React.FC<SidebarProps> = ({ 
  studies, 
  folders,
  currentStudyId, 
  onSelect, 
  onDelete, 
  onNew,
  onNewFolder,
  onDeleteFolder,
  onMoveStudy,
  onExport,
  onExportFolder,
  onImport,
  onToggleFinished,
  className = "" 
}) => {
  const [deleteConfirm, setDeleteConfirm] = useState<{ type: 'study' | 'folder', id: string } | null>(null);
  const [expandedFolders, setExpandedFolders] = useState<Set<string>>(new Set(folders.map(f => f.id)));
  const [showMoveMenu, setShowMoveMenu] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const toggleFolder = (id: string) => {
    const next = new Set(expandedFolders);
    if (next.has(id)) next.delete(id);
    else next.add(id);
    setExpandedFolders(next);
  };

  const handleCreateFolder = () => {
    const name = prompt("Enter folder name:");
    if (name) onNewFolder(name);
  };

  const handleImportClick = () => {
    fileInputRef.current?.click();
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      onImport(file);
      e.target.value = '';
    }
  };

  const renderStudyItem = (study: SavedStudy) => (
    <div
      key={study.id}
      onClick={() => {
        setDeleteConfirm(null);
        onSelect(study);
      }}
      className={`group flex items-start gap-3 p-3 rounded-lg cursor-pointer border transition-all duration-200 relative select-none mb-2
        ${currentStudyId === study.id 
          ? 'bg-white border-indigo-200 shadow-md ring-1 ring-indigo-50' 
          : 'bg-white border-transparent hover:bg-slate-100/80 hover:border-slate-200'
        }`}
    >
      <div className="flex flex-col items-center shrink-0 gap-2">
        <div className={`mt-0.5 p-2 rounded-lg transition-colors ${currentStudyId === study.id ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-100 text-slate-400 group-hover:bg-white'}`}>
          <FileText size={18} />
        </div>
        <button
          onClick={(e) => {
            e.stopPropagation();
            onToggleFinished(study.id);
          }}
          className={`transition-all duration-300 ${study.isFinished ? 'text-emerald-500 scale-110' : 'text-slate-200 hover:text-slate-400'}`}
          title={study.isFinished ? "Study Finished" : "Mark as Finished"}
        >
          <CheckCircle2 size={16} fill={study.isFinished ? "currentColor" : "none"} strokeWidth={study.isFinished ? 3 : 2} className={study.isFinished ? "fill-emerald-500/20" : ""} />
        </button>
      </div>

      <div className="flex-1 min-w-0 pr-6">
        <h3 className={`text-sm font-semibold truncate transition-colors ${currentStudyId === study.id ? 'text-indigo-900' : 'text-slate-700'} ${study.isFinished ? 'opacity-70' : ''}`}>
          {study.name}
        </h3>
        <div className="flex items-center gap-2 mt-1.5">
          <span className="flex items-center gap-1 text-[10px] text-slate-400 font-medium">
            <Calendar size={10} />
            {new Date(study.timestamp).toLocaleDateString(undefined, { month: 'short', day: 'numeric' })}
          </span>
          <span className="text-[10px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded-full border border-slate-200">
            {study.items.length} Items
          </span>
        </div>
      </div>

      {/* Interaction Icons */}
      <div className="absolute right-2 top-2 flex gap-0.5 opacity-0 group-hover:opacity-100 transition-all">
        <button
          onClick={(e) => {
            e.stopPropagation();
            onExport(study);
          }}
          className="p-1.5 text-slate-300 hover:text-emerald-500 hover:bg-emerald-50 rounded-md"
          title="Export JSON"
        >
          <Download size={14} />
        </button>
        <button
          onClick={(e) => {
            e.stopPropagation();
            setShowMoveMenu(showMoveMenu === study.id ? null : study.id);
          }}
          className="p-1.5 text-slate-300 hover:text-indigo-500 hover:bg-indigo-50 rounded-md"
          title="Move to Folder"
        >
          <Move size={14} />
        </button>
        <button
          onClick={(e) => {
            e.stopPropagation();
            setDeleteConfirm({ type: 'study', id: study.id });
          }}
          className="p-1.5 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-md"
          title="Delete Study"
        >
          <Trash2 size={14} />
        </button>
      </div>

      {/* Move Menu Popover */}
      {showMoveMenu === study.id && (
        <div className="absolute right-0 top-10 bg-white border border-slate-200 rounded-xl shadow-2xl z-20 min-w-[160px] p-2 animate-in fade-in zoom-in-95" onClick={e => e.stopPropagation()}>
          <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-2 mb-2">Move to Folder</div>
          <button 
            onClick={() => { onMoveStudy(study.id); setShowMoveMenu(null); }}
            className="w-full text-left px-3 py-2 text-xs font-bold text-slate-600 hover:bg-slate-50 rounded-lg flex items-center gap-2"
          >
            <FolderOpen size={14} className="text-slate-400" /> Uncategorized
          </button>
          {folders.map(f => (
            <button 
              key={f.id}
              onClick={() => { onMoveStudy(study.id, f.id); setShowMoveMenu(null); }}
              className="w-full text-left px-3 py-2 text-xs font-bold text-slate-600 hover:bg-indigo-50 hover:text-indigo-600 rounded-lg flex items-center gap-2"
            >
              <FolderPlus size={14} className="text-indigo-400" /> {f.name}
            </button>
          ))}
        </div>
      )}

      {/* Delete Confirmation Overlay */}
      {deleteConfirm?.type === 'study' && deleteConfirm.id === study.id && (
        <div className="absolute inset-0 bg-red-50/95 backdrop-blur-sm rounded-lg flex items-center justify-between px-3 animate-in fade-in duration-200 z-10">
           <span className="text-xs font-bold text-red-600 flex items-center gap-1">
             <AlertCircle size={12} /> Delete?
           </span>
           <div className="flex gap-2">
             <button onClick={(e) => { e.stopPropagation(); onDelete(study.id); setDeleteConfirm(null); }} className="text-xs bg-red-600 text-white px-2 py-1 rounded hover:bg-red-700 font-medium">Yes</button>
             <button onClick={(e) => { e.stopPropagation(); setDeleteConfirm(null); }} className="text-xs bg-white border border-red-200 text-red-600 px-2 py-1 rounded hover:bg-red-50 font-medium">No</button>
           </div>
        </div>
      )}
    </div>
  );

  return (
    <div className={`bg-white border-r border-slate-200 flex flex-col h-full ${className}`}>
      {/* Hidden Import Input */}
      <input 
        type="file" 
        ref={fileInputRef} 
        onChange={handleFileChange} 
        accept=".json" 
        className="hidden" 
      />

      {/* Sidebar Header */}
      <div className="p-4 border-b border-slate-200 space-y-3">
        <h2 className="text-xs font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
          <Database size={14} />
          Your Studies
        </h2>
        <div className="flex gap-2">
          <button
            onClick={onNew}
            className="flex-1 flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white py-2.5 px-4 rounded-xl text-sm font-medium transition-all shadow-md shadow-indigo-100 transform active:scale-95"
          >
            <Plus size={18} />
            New Study
          </button>
          <button
            onClick={handleImportClick}
            className="p-2.5 bg-slate-100 hover:bg-emerald-50 text-slate-600 hover:text-emerald-600 rounded-xl transition-all active:scale-95"
            title="Import Study JSON"
          >
            <Upload size={18} />
          </button>
          <button
            onClick={handleCreateFolder}
            className="p-2.5 bg-slate-100 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-xl transition-all active:scale-95"
            title="New Folder"
          >
            <FolderPlus size={18} />
          </button>
        </div>
      </div>

      {/* Folders and Studies List */}
      <div className="flex-1 overflow-y-auto custom-scrollbar p-3 bg-slate-50/50">
        {folders.length === 0 && studies.length === 0 ? (
          <div className="text-center py-12 px-4">
            <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-100 text-slate-300 mb-4">
              <FolderOpen size={32} strokeWidth={1.5} />
            </div>
            <p className="text-sm text-slate-600 font-medium">No saved studies</p>
            <p className="text-xs text-slate-400 mt-2 leading-relaxed">
              Create a new RCM analysis, import a shared file, or add a folder.
            </p>
          </div>
        ) : (
          <div className="space-y-4">
            {/* Folder Sections */}
            {folders.map(folder => {
              const folderStudies = studies.filter(s => s.folderId === folder.id);
              const isExpanded = expandedFolders.has(folder.id);

              return (
                <div key={folder.id} className="space-y-1">
                  <div className={`group flex items-center gap-2 p-2 rounded-xl transition-all cursor-pointer ${isExpanded ? 'bg-indigo-50/40' : 'hover:bg-white'}`}>
                    <button onClick={() => toggleFolder(folder.id)} className="p-1 text-slate-400 hover:text-indigo-600">
                      {isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
                    </button>
                    <div onClick={() => toggleFolder(folder.id)} className="flex-1 flex items-center gap-2">
                      <FolderPlus size={16} className={`${isExpanded ? 'text-indigo-600' : 'text-slate-400'}`} />
                      <span className={`text-xs font-black uppercase tracking-widest ${isExpanded ? 'text-indigo-700' : 'text-slate-500'}`}>{folder.name}</span>
                      <span className="text-[10px] bg-white px-1.5 py-0.5 rounded border border-slate-100 text-slate-400 font-bold">{folderStudies.length}</span>
                    </div>
                    <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                      <button 
                        onClick={(e) => { e.stopPropagation(); onExportFolder(folder); }}
                        className="p-1 text-slate-300 hover:text-indigo-600 transition-all"
                        title="Export Folder Bundle"
                      >
                        <Download size={12} />
                      </button>
                      <button 
                        onClick={(e) => { e.stopPropagation(); setDeleteConfirm({ type: 'folder', id: folder.id }); }}
                        className="p-1 text-slate-300 hover:text-red-500 transition-all"
                        title="Delete Folder"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </div>

                  {isExpanded && (
                    <div className="pl-4 border-l border-indigo-100/50 ml-4 animate-in slide-in-from-top-1 duration-200">
                      {folderStudies.length === 0 ? (
                        <div className="py-2 px-3 text-[10px] text-slate-300 italic font-medium">Empty Folder</div>
                      ) : (
                        folderStudies.map(renderStudyItem)
                      )}
                    </div>
                  )}

                  {/* Folder Delete Confirmation */}
                  {deleteConfirm?.type === 'folder' && deleteConfirm.id === folder.id && (
                    <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 p-4">
                      <div className="bg-white p-6 rounded-3xl shadow-2xl border border-slate-100 max-w-sm w-full text-center">
                        <div className="w-12 h-12 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto mb-4">
                          <AlertCircle size={24} />
                        </div>
                        <h4 className="text-lg font-black text-slate-900 uppercase tracking-tighter mb-2">Delete Folder?</h4>
                        <p className="text-sm text-slate-500 mb-6">Studies inside will become <b>Uncategorized</b>. This action cannot be undone.</p>
                        <div className="flex gap-3">
                          <button onClick={() => { onDeleteFolder(folder.id); setDeleteConfirm(null); }} className="flex-1 py-3 bg-red-600 text-white rounded-xl text-xs font-black uppercase tracking-widest hover:bg-red-700 transition-all">Yes, Delete</button>
                          <button onClick={() => setDeleteConfirm(null)} className="flex-1 py-3 bg-slate-100 text-slate-600 rounded-xl text-xs font-black uppercase tracking-widest hover:bg-slate-200 transition-all">Cancel</button>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}

            {/* Uncategorized Section */}
            <div>
              <div className="flex items-center gap-2 p-2 mb-2">
                <FolderOpen size={16} className="text-slate-300" />
                <span className="text-xs font-black text-slate-400 uppercase tracking-widest">Uncategorized</span>
              </div>
              {studies.filter(s => !s.folderId).map(renderStudyItem)}
            </div>
          </div>
        )}
      </div>

      {/* Footer Info */}
      <div className="p-4 border-t border-slate-200 bg-slate-50 text-[10px] text-slate-400 text-center font-bold tracking-tight">
        Reliability Intelligence Repository
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsLoadingExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId, // Preserve folder association
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // First, un-group studies associated with this folder
      const studiesToUpdate = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToUpdate) {
        await saveStudyToDB({ ...study, folderId: undefined });
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      // If we're currently viewing this study, update current state too
      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportFolder = (folder: Folder) => {
    const folderStudies = savedStudies.filter(s => s.folderId === folder.id);
    const bundle = {
      type: 'folder_bundle',
      folder: folder,
      studies: folderStudies
    };
    const dataStr = JSON.stringify(bundle, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${folder.name.replace(/\s+/g, '_')}_RCM_Bundle.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedData = JSON.parse(content);

        if (importedData.type === 'folder_bundle') {
          // Process folder bundle
          const newFolderId = `folder-imported-${Date.now()}`;
          const newFolder: Folder = {
            ...importedData.folder,
            id: newFolderId,
            timestamp: Date.now()
          };

          await saveFolderToDB(newFolder);

          for (const study of importedData.studies) {
            const finalStudy: SavedStudy = {
              ...study,
              id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
              timestamp: Date.now(),
              folderId: newFolderId
            };
            await saveStudyToDB(finalStudy);
          }

          const [freshFolders, freshStudies] = await Promise.all([
            getAllFolders(),
            getAllStudies()
          ]);
          setFolders(freshFolders);
          setSavedStudies(freshStudies);

        } else {
          // Process standard study
          const importedStudy = importedData as SavedStudy;
          if (!importedStudy.name || !importedStudy.items) {
            throw new Error("Invalid study format");
          }

          const finalStudy: SavedStudy = {
            ...importedStudy,
            id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            timestamp: Date.now(),
            folderId: undefined
          };

          await saveStudyToDB(finalStudy);
          const freshStudies = await getAllStudies();
          setSavedStudies(freshStudies);
          handleLoadStudy(finalStudy);
        }

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import. Ensure the file is a valid RCM Pro JSON or Bundle.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onExportFolder={handleExportFolder}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? "Synthesizing Document..." : "Extract & Structure Context"}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 shadow-indigo-300 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate FMEA Synthesis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished]);

  // Load studies and handle welcome modal visibility
  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) {
        setShowWelcome(true);
      }

      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsLoadingExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId, // Preserve folder association
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // Delete all studies associated with this folder
      const studiesToDelete = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToDelete) {
        await deleteStudyFromDB(study.id);
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);

      // Reset view if active study was deleted as part of the folder
      if (currentStudyId && studiesToDelete.some(s => s.id === currentStudyId)) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      // If we're currently viewing this study, update current state too
      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportFolder = (folder: Folder) => {
    const folderStudies = savedStudies.filter(s => s.folderId === folder.id);
    const bundle = {
      type: 'folder_bundle',
      folder: folder,
      studies: folderStudies
    };
    const dataStr = JSON.stringify(bundle, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${folder.name.replace(/\s+/g, '_')}_RCM_Bundle.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedData = JSON.parse(content);

        if (importedData.type === 'folder_bundle') {
          // Process folder bundle
          const newFolderId = `folder-imported-${Date.now()}`;
          const newFolder: Folder = {
            ...importedData.folder,
            id: newFolderId,
            timestamp: Date.now()
          };

          await saveFolderToDB(newFolder);

          for (const study of importedData.studies) {
            const finalStudy: SavedStudy = {
              ...study,
              id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
              timestamp: Date.now(),
              folderId: newFolderId
            };
            await saveStudyToDB(finalStudy);
          }

          const [freshFolders, freshStudies] = await Promise.all([
            getAllFolders(),
            getAllStudies()
          ]);
          setFolders(freshFolders);
          setSavedStudies(freshStudies);

        } else {
          // Process standard study
          const importedStudy = importedData as SavedStudy;
          if (!importedStudy.name || !importedStudy.items) {
            throw new Error("Invalid study format");
          }

          const finalStudy: SavedStudy = {
            ...importedStudy,
            id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            timestamp: Date.now(),
            folderId: undefined
          };

          await saveStudyToDB(finalStudy);
          const freshStudies = await getAllStudies();
          setSavedStudies(freshStudies);
          handleLoadStudy(finalStudy);
        }

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import. Ensure the file is a valid RCM Pro JSON or Bundle.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onExportFolder={handleExportFolder}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
