  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  // Auto-save refs
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);
  const methodologyRef = useRef(methodology);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
    methodologyRef.current = methodology;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished, methodology]);

  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) setShowWelcome(true);
      try {
        const [studies, fetchedFolders] = await Promise.all([getAllStudies(), getAllFolders()]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies.");
      }
    };
    initData();
  }, []);

  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) handleSaveStudy(true);
    }, 30000);
    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
    localStorage.setItem('rcm_welcome_shown', 'true');
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) { setError("Failed to read file."); }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) { setError("Document analysis failed."); } finally { setIsLoadingExtracting(false); }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }
    setIsLoading(true);
    setError(null);
    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }
    try {
      const data = await generateRCMAnalysis(contextText, fileData, methodology, isMerging ? (results || []) : []);
      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }
    } catch (err: any) { setError(err.message || "An error occurred."); } finally { setIsLoading(false); }
  };

  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const currentMethodology = methodologyRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const idToSave = currentId || `study-${Date.now()}`;
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: currentName.trim() || "Untitled Analysis",
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      methodology: currentMethodology,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId,
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) setCurrentStudyId(idToSave);
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) { if (!isAutoSave) setError("Failed to save study."); }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setMethodology(study.methodology || 'Classical');
    setFileData(null);
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setMethodology('Classical');
    setError(null);
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) setHistory(prev => [...prev.slice(-29), results]);
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={deleteStudyFromDB} 
          onNew={handleNewStudy} 
          onNewFolder={saveFolderToDB as any}
          onDeleteFolder={deleteFolderFromDB}
          onMoveStudy={(id, fId) => handleSaveStudy(true)}
          onExport={() => {}}
          onExportFolder={() => {}}
          onImport={() => {}}
          onToggleFinished={() => {}}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600' : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Saved" : "Save"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">RCM Intelligence Hub</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Synthesize technical operational data into standardized reliability strategies.</p>
              </div>
            )}

            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex justify-between items-center overflow-x-auto">
                <div className="flex gap-8">
                  <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Synthesis</button>
                  <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge</button>
                </div>

                {/* METHODOLOGY SWITCHER */}
                <div className="pb-5 pr-2">
                   <div className="flex bg-slate-100 p-1 rounded-xl border border-slate-200 shadow-inner">
                      <button 
                        onClick={() => setMethodology('Classical')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${methodology === 'Classical' ? 'bg-white text-indigo-600 shadow-sm ring-1 ring-black/5' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        <Layers size={14} /> Classical RCM
                      </button>
                      <button 
                        onClick={() => setMethodology('Component')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${methodology === 'Component' ? 'bg-white text-emerald-600 shadow-sm ring-1 ring-black/5' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        <Component size={14} /> Component-Centric
                      </button>
                   </div>
                </div>
              </div>

              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Asset Parameters</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite]"></div><div className="relative flex items-center gap-2"><Sparkles size={16} className="text-white fill-white animate-pulse" /><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="P-101 Centrifugal Pump analysis..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Upload documentation</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate">{fileData.name}</p></div><button onClick={() => setFileData(null)} className="p-3 text-slate-300 hover:text-red-500"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && <button onClick={handleExtractContext} disabled={isExtracting} className="flex items-center gap-3 px-8 py-3 bg-white text-indigo-600 border border-indigo-100 rounded-2xl text-[10px] font-black uppercase mx-auto transition-all">{isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />} Extract Context</button>}
                  </div>
                )}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">
                  {results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded" /><span className="text-xs font-bold text-slate-600 uppercase">Merge items</span></label>)}
                  <button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all ${isLoading ? 'bg-indigo-400' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                    {isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}
                    {isLoading ? "Synthesizing..." : (isMerging ? "Append Analysis" : "Initiate Strategy Generation")}
                  </button>
                </div>
              </div>
            </div>
            {results && <AnalysisResult methodology={methodology} data={results} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel, AnalysisMethodology } from '../types';
import { generateInspectionSheet, generateComponentIntel } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, Copy, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, LayoutList, Target, Palette, Image as ImageIcon, Box,
  Layers,
  Component
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  methodology: AnalysisMethodology;
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
}

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, methodology, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color'; direction: 'asc' | 'desc' }>({ key: 'function', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [generatingIntel, setGeneratingIntel] = useState(false);
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());
  const [copied, setCopied] = useState(false);

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => !!item);
    if (matrixFilter) result = result.filter(item => (item.severity === matrixFilter.s && item.occurrence === matrixFilter.o));
    if (barFilter) result = result.filter(item => item.id === barFilter);
    if (searchFilters.component) result = result.filter(item => item.component.toLowerCase().includes(searchFilters.component.toLowerCase()));

    result.sort((a, b) => {
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      const aVal = a[sortConfig.key as keyof RCMItem] ?? '';
      const bVal = b[sortConfig.key as keyof RCMItem] ?? '';
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  // For Classical RCM view, we group data
  const groupedData = useMemo(() => {
    if (methodology !== 'Classical') return null;
    const groups: Record<string, Record<string, RCMItem[]>> = {};
    processedData.forEach(item => {
      const func = item.function || "System Function";
      const fail = item.functionalFailure || "Functional Failure";
      if (!groups[func]) groups[func] = {};
      if (!groups[func][fail]) groups[func][fail] = [];
      groups[func][fail].push(item);
    });
    return groups;
  }, [processedData, methodology]);

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    setSortConfig({ key, direction });
  };

  const handleDelete = (id: string) => onUpdate(data.filter(item => item.id !== id));

  const handleEdit = (item: RCMItem) => { setEditingId(item.id); setEditForm({ ...item }); };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const updated = { ...editForm, rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1), isNew: false };
    onUpdate(data.map(item => item.id === editingId ? updated : item));
    setEditingId(null); setEditForm(null);
  };

  const handleChange = (field: keyof RCMItem, value: any) => editForm && setEditForm({ ...editForm, [field]: value });

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      setViewSheet({ item: newData.find(d => d.id === item.id)! });
    } catch (e) { alert("Generation failed"); } finally {
      setRegeneratingIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const handleCopy = async () => {
    const text = processedData.map(i => `${i.function}\t${i.failureMode}\t${i.component}\t${i.rpn}`).join('\n');
    await navigator.clipboard.writeText(text);
    setCopied(true); setTimeout(() => setCopied(false), 2000);
  };

  const renderTableBody = () => {
    if (methodology === 'Classical' && groupedData) {
      return Object.entries(groupedData).map(([func, failures]) => (
        <React.Fragment key={func}>
          <tr className="bg-slate-900 text-white"><td colSpan={9} className="px-6 py-3"><div className="flex items-center gap-3"><Tag size={14} className="text-indigo-400" /><span className="text-xs font-black uppercase tracking-[0.2em]">Function: {func}</span></div></td></tr>
          {Object.entries(failures).map(([fail, items]) => (
            <React.Fragment key={fail}>
              <tr className="bg-indigo-50/50"><td colSpan={9} className="px-10 py-2 border-b border-indigo-100"><div className="flex items-center gap-3"><AlertTriangle size={12} className="text-amber-600" /><span className="text-[11px] font-bold text-slate-700 uppercase tracking-tight italic">Functional Failure: {fail}</span></div></td></tr>
              {items.map(renderItemRow)}
            </React.Fragment>
          ))}
        </React.Fragment>
      ));
    }
    return processedData.map(renderItemRow);
  };

  const renderItemRow = (item: RCMItem) => {
    const isEditing = editingId === item.id;
    if (isEditing && editForm) {
      return (
        <tr key={item.id} className="bg-indigo-50/30">
          <td className="px-6 py-4"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full p-1 border rounded text-xs" /></td>
          <td className="px-6 py-4"><input value={editForm.component} onChange={(e) => handleChange('component', e.target.value)} className="w-full p-1 border rounded text-xs" /></td>
          <td className="px-2 py-4 bg-white/50 border-l"><input type="number" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-12 p-1 border rounded text-xs" /></td>
          <td className="px-2 py-4 bg-white/50"><input type="number" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-12 p-1 border rounded text-xs" /></td>
          <td className="px-2 py-4 bg-white/50"><input type="number" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-12 p-1 border rounded text-xs" /></td>
          <td className="px-4 py-4 bg-slate-50 font-black text-indigo-600 text-center">{editForm.severity * editForm.occurrence * editForm.detection}</td>
