}

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, methodology, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn'; direction: 'asc' | 'desc' }>({ key: 'rpn', direction: 'desc' });

  const processedData = useMemo(() => {
    let result = [...data];
    if (matrixFilter) result = result.filter(item => item.severity === matrixFilter.s && item.occurrence === matrixFilter.o);

    result.sort((a, b) => {
      const aVal = a[sortConfig.key as keyof RCMItem] ?? 0;
      const bVal = b[sortConfig.key as keyof RCMItem] ?? 0;
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, sortConfig]);

  const groupedData = useMemo(() => {
    if (methodology !== 'Classical') return null;
    const groups: Record<string, Record<string, RCMItem[]>> = {};
    processedData.forEach(item => {
      const func = item.function || "General Function";
      const fail = item.functionalFailure || "Undefined Failure";
      if (!groups[func]) groups[func] = {};
      if (!groups[func][fail]) groups[func][fail] = [];
      groups[func][fail].push(item);
    });
    return groups;
  }, [processedData, methodology]);

  const handleEdit = (item: RCMItem) => { setEditingId(item.id); setEditForm({...item}); };
  const handleSave = () => {
    if (!editForm) return;
    const updated = {...editForm, rpn: editForm.severity * editForm.occurrence * editForm.detection};
    onUpdate(data.map(i => i.id === updated.id ? updated : i));
    setEditingId(null);
  };

  const renderRow = (item: RCMItem) => {
    const isEditing = editingId === item.id;
    const style = getRPNColorStyle(item.rpn);

    if (isEditing && editForm) {
      return (
        <tr key={item.id} className="bg-indigo-50/30">
          <td className="px-6 py-4"><textarea className="w-full p-1 border rounded text-xs" value={editForm.failureMode} onChange={e => setEditForm({...editForm, failureMode: e.target.value})} /></td>
          <td className="px-6 py-4"><input className="w-full p-1 border rounded text-xs" value={editForm.component} onChange={e => setEditForm({...editForm, component: e.target.value})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.severity} onChange={e => setEditForm({...editForm, severity: parseInt(e.target.value)})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.occurrence} onChange={e => setEditForm({...editForm, occurrence: parseInt(e.target.value)})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.detection} onChange={e => setEditForm({...editForm, detection: parseInt(e.target.value)})} /></td>
          <td className="px-4 py-4 text-center font-black">{editForm.severity * editForm.occurrence * editForm.detection}</td>
          <td className="px-6 py-4"><input className="w-full p-1 border rounded text-xs" value={editForm.maintenanceTask} onChange={e => setEditForm({...editForm, maintenanceTask: e.target.value})} /></td>
          <td colSpan={2} className="px-6 py-4 text-right">
            <button onClick={handleSave} className="p-2 text-indigo-600"><Save size={16}/></button>
            <button onClick={() => setEditingId(null)} className="p-2 text-slate-400"><X size={16}/></button>
          </td>
        </tr>
      );
    }

    return (
      <tr key={item.id} className="group hover:bg-slate-50 transition-all">
        <td className="px-6 py-4">
          <p className="text-xs font-bold text-slate-800 uppercase leading-relaxed">{item.failureMode}</p>
