            {item.component} <Info size={12} className="text-slate-300" />
          </button>
        </td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.severity}</td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.occurrence}</td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.detection}</td>
        <td className="px-4 py-4">
          <div className={`w-full py-1 rounded text-center font-black text-xs border ${style.bg} ${style.text} border-black/5`}>{item.rpn}</div>
        </td>
        <td className="px-6 py-4">
          <div className="flex flex-col">
            <span className="text-[11px] font-black text-slate-900 uppercase leading-none">{item.maintenanceTask}</span>
            <span className="text-[9px] text-indigo-500 font-bold uppercase mt-1">{item.interval} • {item.taskType}</span>
          </div>
        </td>
        <td className="px-6 py-4 text-center">
          <button onClick={() => setViewSheet({item})} className="p-2 bg-slate-100 text-slate-400 hover:text-indigo-600 rounded-lg"><ClipboardList size={16}/></button>
        </td>
