import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder, AnalysisMethodology } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, Upload, Type, Zap, Loader2, FileCheck, Trash2, Menu, Save, Check, AlertTriangle, BookOpen, Sparkles, GitBranch, Undo2, PlusCircle, FileSearch, CheckCircle2, Layers, Component as ComponentIcon
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [methodology, setMethodology] = useState<AnalysisMethodology>('Classical');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);
  const [history, setHistory] = useState<RCMItem[][]>([]);
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  const [showSOD, setShowSOD] = useState(false);
  const [showBuilder, setShowBuilder] = useState(false);
  const [showLogic, setShowLogic] = useState(false);

  useEffect(() => {
    const init = async () => {
      const shown = localStorage.getItem('rcm_welcome_shown');
      if (!shown) setShowWelcome(true);
      const [studies, fetchedFolders] = await Promise.all([getAllStudies(), getAllFolders()]);
      setSavedStudies(studies);
      setFolders(fetchedFolders);
    };
    init();
  }, []);

  const handleGenerate = async () => {
    if (!contextText && !fileData) { setError("Context required."); return; }
    setIsLoading(true); setError(null);
    try {
      const data = await generateRCMAnalysis(contextText, fileData, methodology, isMerging ? (results || []) : []);
      if (isMerging && results) setResults([...results, ...data]);
      else setResults(data);
    } catch (err: any) { setError(err.message || "Error generating."); } finally { setIsLoading(false); }
  };

  const handleSaveStudy = async (isAuto = false) => {
    if (!results && !contextText) return;
    const study: SavedStudy = {
      id: currentStudyId || `study-${Date.now()}`,
      name: studyName || "Untitled",
      timestamp: Date.now(),
      items: results || [],
      contextText,
      methodology
    };
    await saveStudyToDB(study);
    setSavedStudies(await getAllStudies());
    setCurrentStudyId(study.id);
    setJustSaved(true);
    setTimeout(() => setJustSaved(false), 2000);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={() => { setShowWelcome(false); localStorage.setItem('rcm_welcome_shown', 'true'); }} />
      <Sidebar studies={savedStudies} folders={folders} currentStudyId={currentStudyId} 
        onSelect={(s) => { setResults(s.items); setContextText(s.contextText); setCurrentStudyId(s.id); setStudyName(s.name); setMethodology(s.methodology || 'Classical'); }}
        onDelete={async (id) => { await deleteStudyFromDB(id); setSavedStudies(await getAllStudies()); }} 
        onNew={() => { setResults(null); setContextText(''); setCurrentStudyId(null); setStudyName("Untitled Analysis"); }}
        onNewFolder={async (n) => { await saveFolderToDB({id: `f-${Date.now()}`, name: n, timestamp: Date.now()}); setFolders(await getAllFolders()); }}
        onDeleteFolder={async (id) => { await deleteFolderFromDB(id); setFolders(await getAllFolders()); }}
        onMoveStudy={() => {}} onExport={() => {}} onExportFolder={() => {}} onImport={() => {}} onToggleFinished={() => {}}
      />
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="h-20 bg-white border-b border-slate-200 px-6 flex items-center justify-between">
          <div className="flex items-center gap-4">
             <input type="text" value={studyName} onChange={e => setStudyName(e.target.value)} className="text-xl font-black text-slate-800 bg-transparent focus:outline-none" />
          </div>
          <div className="flex items-center gap-3">
             <button onClick={() => handleSaveStudy()} className={`flex items-center gap-2 px-6 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${justSaved ? 'bg-emerald-600 text-white' : 'bg-indigo-600 text-white'}`}>
                {justSaved ? <Check size={16}/> : <Save size={16}/>} {justSaved ? 'Saved' : 'Save'}
             </button>
          </div>
        </header>
        <main className="flex-1 overflow-y-auto p-8">
          <div className="max-w-7xl mx-auto space-y-8">
            <div className="bg-white rounded-3xl p-8 border border-slate-200 shadow-sm">
              <div className="flex justify-between items-center mb-6">
                <div className="flex gap-4">
                  <button onClick={() => setActiveTab('manual')} className={`text-xs font-black uppercase tracking-widest pb-2 border-b-2 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}>Synthesis</button>
                  <button onClick={() => setActiveTab('upload')} className={`text-xs font-black uppercase tracking-widest pb-2 border-b-2 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}>Knowledge</button>
                </div>
                <div className="flex bg-slate-100 p-1 rounded-xl">
                  <button onClick={() => setMethodology('Classical')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase ${methodology === 'Classical' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-400'}`}><Layers size={14}/> Classical</button>
                  <button onClick={() => setMethodology('Component')} className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase ${methodology === 'Component' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}><ComponentIcon size={14}/> Component</button>
                </div>
              </div>
              <textarea value={contextText} onChange={e => setContextText(e.target.value)} className="w-full h-40 p-4 bg-slate-50 border border-slate-200 rounded-2xl outline-none focus:border-indigo-500 transition-all font-medium text-slate-700" placeholder="Operational Context..."/>
              <div className="mt-6 flex justify-end">
                <button onClick={handleGenerate} disabled={isLoading} className="flex items-center gap-2 px-10 py-4 bg-indigo-600 text-white rounded-2xl text-xs font-black uppercase tracking-[0.2em] shadow-xl hover:bg-indigo-700 transition-all">
                  {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Zap size={20} />}
                  {isLoading ? "Synthesizing..." : "Initiate Strategy Generation"}
                </button>
              </div>
            </div>
            {results && <AnalysisResult methodology={methodology} data={results} onUpdate={setResults} onUndo={() => {}} canUndo={false} />}
          </div>
        </main>
      </div>
    </div>
  );
};

