export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  methodology: AnalysisMethodology,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  try {
    const apiKey = process.env.API_KEY;
    if (!apiKey) throw new Error("API_KEY not set");

    // Fix: Create instance right before use
    const ai = new GoogleGenAI({ apiKey });
    const parts: any[] = [];

    if (fileData) {
      parts.push({ inlineData: { mimeType: fileData.mimeType, data: fileData.data } });
    }
    if (contextText) {
      parts.push({ text: `Operational Context:\n${contextText}` });
    }

    const methodologyPrompt = methodology === 'Classical' 
      ? "Perform a CLASSICAL RCM Analysis (SAE JA1011 compliant). Focus on System Functions first, then Functional Failures, then Failure Modes."
      : "Perform a COMPONENT-BASED RCM/FMEA. Focus on individual technical components and their specific failure modes.";

    parts.push({
      text: `${methodologyPrompt} 
      Avoid duplicating existing items: ${existingItems.map(i => i.failureMode).join(", ")}.
      Target 15-20 detailed failure modes. Use ISO 14224 coding for classification.`
    });

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: { parts },
      config: {
        responseMimeType: "application/json",
        responseSchema: rcmSchema,
        thinkingConfig: { thinkingBudget: 24000 }
      }
    });

    const rawData = JSON.parse(response.text || "[]") as Omit<RCMItem, 'id' | 'rpn'>[];
    return rawData.map((item, index) => ({
      ...item,
      rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
      id: `rcm-${Date.now()}-${index}`,
      isNew: true
    }));
  } catch (error) {
    console.error("RCM Gen Error", error);
    throw error;
  }
};

