                  <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[10px] font-black uppercase tracking-widest border-b-2 transition-all ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}>Knowledge</button>
