                      </button>
                      <button 
                        onClick={() => setMethodology('Component')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${methodology === 'Component' ? 'bg-white text-emerald-600 shadow-sm' : 'text-slate-400'}`}
