      <SODReference isOpen={showSOD} onClose={() => setShowSOD(false)} onUndo={() => {}} canUndo={false} />
      <DecisionLogicModal isOpen={showLogic} onClose={() => setShowLogic(false)} onUndo={() => {}} canUndo={false} />
      <AICopilot data={results} onUpdate={setResults} />
