                               <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest italic">Functional Failure: {fail}</span>
                            </div>
                          </td>
                        </tr>
                        {items.map(renderRow)}
                      </React.Fragment>
                    ))}
                  </React.Fragment>
                ))
              ) : (
                processedData.map(renderRow)
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Logic Trees & Reference Overlays */}
      {selectedIntel && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setSelectedIntel(null)}>
