                           <table className="w-full text-left">
                              <thead className="bg-slate-900 text-[10px] font-black uppercase text-slate-400">
                                 <tr>
                                    <th className="px-8 py-4 w-16 text-center">Step</th>
                                    <th className="px-8 py-4">Action Description</th>
                                    <th className="px-8 py-4 w-40">Method</th>
                                    <th className="px-8 py-4 w-60">Criteria</th>
