                  <button onClick={() => setViewSheet(null)} className="px-12 py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all shadow-xl active:scale-95">Close Protocol</button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel, AnalysisMethodology } from '../types';
import { generateInspectionSheet, generateComponentIntel } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Copy, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, LayoutList, Box, Layers, Component as ComponentIcon,
  Target
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  methodology: AnalysisMethodology;
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
}

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, methodology, onUpdate, onUndo, canUndo }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn'; direction: 'asc' | 'desc' }>({ key: 'rpn', direction: 'desc' });
  const [copied, setCopied] = useState(false);

  const processedData = useMemo(() => {
    let result = [...(data || [])].filter(Boolean);
    if (matrixFilter) result = result.filter(item => item.severity === matrixFilter.s && item.occurrence === matrixFilter.o);

    result.sort((a, b) => {
      const aVal = a[sortConfig.key as keyof RCMItem] ?? 0;
      const bVal = b[sortConfig.key as keyof RCMItem] ?? 0;
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, sortConfig]);

  const groupedData = useMemo(() => {
    if (methodology !== 'Classical') return null;
    const groups: Record<string, Record<string, RCMItem[]>> = {};
    processedData.forEach(item => {
      const func = item.function || "General Asset Function";
      const fail = item.functionalFailure || "Undefined Failure";
      if (!groups[func]) groups[func] = {};
      if (!groups[func][fail]) groups[func][fail] = [];
      groups[func][fail].push(item);
    });
    return groups;
  }, [processedData, methodology]);

  const handleEdit = (item: RCMItem) => { setEditingId(item.id); setEditForm({...item}); };
  const handleSave = () => {
    if (!editForm) return;
    const updated = {...editForm, rpn: editForm.severity * editForm.occurrence * editForm.detection};
    onUpdate(data.map(i => i.id === updated.id ? updated : i));
    setEditingId(null);
  };

  const handleCopy = async () => {
    const text = processedData.map(i => `${i.function}\t${i.failureMode}\t${i.maintenanceTask}`).join('\n');
    await navigator.clipboard.writeText(text);
    setCopied(true); setTimeout(() => setCopied(false), 2000);
  };

  const renderRow = (item: RCMItem) => {
    const isEditing = editingId === item.id;
    const style = getRPNColorStyle(item.rpn);

    if (isEditing && editForm) {
      return (
        <tr key={item.id} className="bg-indigo-50/30">
          <td className="px-6 py-4"><textarea className="w-full p-1 border rounded text-xs" value={editForm.failureMode} onChange={e => setEditForm({...editForm, failureMode: e.target.value})} /></td>
          <td className="px-6 py-4"><input className="w-full p-1 border rounded text-xs" value={editForm.component} onChange={e => setEditForm({...editForm, component: e.target.value})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.severity} onChange={e => setEditForm({...editForm, severity: parseInt(e.target.value)})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.occurrence} onChange={e => setEditForm({...editForm, occurrence: parseInt(e.target.value)})} /></td>
          <td className="px-2 py-4"><input type="number" className="w-12 p-1 border rounded text-xs" value={editForm.detection} onChange={e => setEditForm({...editForm, detection: parseInt(e.target.value)})} /></td>
          <td className="px-4 py-4 text-center font-black">{editForm.severity * editForm.occurrence * editForm.detection}</td>
          <td className="px-6 py-4"><input className="w-full p-1 border rounded text-xs" value={editForm.maintenanceTask} onChange={e => setEditForm({...editForm, maintenanceTask: e.target.value})} /></td>
          <td colSpan={2} className="px-6 py-4 text-right">
            <div className="flex justify-end gap-2">
               <button onClick={handleSave} className="p-2 bg-indigo-600 text-white rounded-lg shadow-sm"><Save size={14}/></button>
               <button onClick={() => setEditingId(null)} className="p-2 bg-slate-200 text-slate-600 rounded-lg"><X size={14}/></button>
            </div>
          </td>
        </tr>
      );
    }

    return (
      <tr key={item.id} className="group hover:bg-slate-50 transition-all border-b border-slate-100 last:border-0">
        <td className="px-6 py-4">
          <div className="flex flex-col">
            <p className="text-xs font-bold text-slate-800 uppercase tracking-tight">{item.failureMode}</p>
            <p className="text-[10px] text-slate-400 mt-0.5 italic line-clamp-1">{item.failureEffect}</p>
          </div>
        </td>
        <td className="px-6 py-4">
          <button onClick={() => setSelectedIntel(item)} className="text-[11px] font-black hover:text-indigo-600 transition-colors flex items-center gap-1.5 uppercase">
            {item.component} <Info size={12} className="text-slate-300" />
          </button>
        </td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.severity}</td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.occurrence}</td>
        <td className="px-2 py-4 text-center font-bold text-slate-600">{item.detection}</td>
        <td className="px-4 py-4">
          <div className={`w-full py-1.5 rounded-lg text-center font-black text-[10px] border shadow-sm ${style.bg} ${style.text} border-black/5`}>{item.rpn}</div>
        </td>
        <td className="px-6 py-4">
          <div className="flex items-center gap-3">
            <div className="p-1.5 bg-slate-100 rounded-lg text-slate-400 group-hover:text-indigo-600 transition-colors"><Wrench size={14} /></div>
            <div className="flex flex-col">
              <span className="text-[11px] font-black text-slate-900 uppercase leading-none tracking-tight">{item.maintenanceTask}</span>
              <span className="text-[9px] text-indigo-500 font-bold uppercase mt-1">{item.interval} • {item.taskType}</span>
            </div>
          </div>
        </td>
        <td className="px-6 py-4 text-center">
          <button onClick={() => setViewSheet({item})} className={`p-2 rounded-xl transition-all shadow-sm ${item.inspectionSheet ? 'bg-emerald-50 text-emerald-600 hover:bg-emerald-100' : 'bg-slate-100 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50'}`}>
            <ClipboardList size={18}/>
          </button>
        </td>
        <td className="px-6 py-4 text-right">
          <div className="flex justify-end gap-1.5 opacity-0 group-hover:opacity-100 transition-opacity">
            <button onClick={() => handleEdit(item)} className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-white rounded-lg transition-all shadow-sm"><Pencil size={14}/></button>
            <button onClick={() => onUpdate(data.filter(i => i.id !== item.id))} className="p-2 text-slate-400 hover:text-red-500 hover:bg-white rounded-lg transition-all shadow-sm"><Trash2 size={14}/></button>
          </div>
        </td>
      </tr>
    );
  };

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      {/* Dynamic Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-200 flex items-center gap-5">
          <div className={`p-4 rounded-2xl ${methodology === 'Classical' ? 'bg-indigo-50 text-indigo-600' : 'bg-emerald-50 text-emerald-600'} shadow-inner`}>
            {methodology === 'Classical' ? <Layers size={22}/> : <ComponentIcon size={22}/>}
          </div>
          <div>
             <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">Strategy Tab</p>
             <h4 className="text-sm font-black uppercase text-slate-900 leading-none mt-1">{methodology === 'Classical' ? 'Classical RCM' : 'Component-Based'}</h4>
          </div>
        </div>
        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-200 flex items-center gap-5">
          <div className="p-4 bg-red-50 text-red-600 rounded-2xl shadow-inner"><AlertOctagon size={22}/></div>
          <div><p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">Critical Failures</p><h4 className="text-xl font-black text-slate-900 mt-1 leading-none">{data.filter(i => i.rpn >= 100).length}</h4></div>
        </div>
        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-200 flex items-center gap-5">
          <div className="p-4 bg-amber-50 text-amber-600 rounded-2xl shadow-inner"><ListChecks size={22}/></div>
          <div><p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">Total Items</p><h4 className="text-xl font-black text-slate-900 mt-1 leading-none">{data.length}</h4></div>
        </div>
        <div className="bg-white p-5 rounded-[2rem] shadow-sm border border-slate-200 flex items-center gap-5">
          <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl shadow-inner"><Target size={22}/></div>
          <div><p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em]">Highest RPN</p><h4 className="text-xl font-black text-slate-900 mt-1 leading-none">{Math.max(...data.map(i => i.rpn), 0)}</h4></div>
        </div>
      </div>

      {/* Main Analysis Hub */}
      <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-8 bg-slate-50/50 border-b border-slate-200 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-4">
             <div className="p-3 bg-indigo-600 rounded-2xl shadow-lg ring-4 ring-indigo-50"><FileText size={20} className="text-white"/></div>
             <div>
               <h3 className="text-lg font-black text-slate-900 uppercase tracking-tighter leading-none">Maintenance Strategy Hub</h3>
               <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1.5">{methodology === 'Classical' ? 'Functional Logic Tree' : 'Component FMECA Grid'}</p>
             </div>
          </div>
          <div className="flex items-center gap-3">
             <button onClick={handleCopy} className="flex items-center gap-2 px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-[10px] font-black uppercase tracking-widest text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 transition-all shadow-sm">
                {copied ? <CheckCircle size={14} className="text-emerald-500" /> : <Copy size={14}/>} {copied ? 'Copied' : 'Export Table'}
             </button>
             <button onClick={() => setMatrixFilter(null)} disabled={!matrixFilter} className={`flex items-center gap-2 px-5 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${matrixFilter ? 'bg-amber-50 text-amber-600 border border-amber-200 shadow-sm' : 'text-slate-200'}`}>
                <FilterX size={14}/> Clear Filters
             </button>
          </div>
        </div>

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left table-fixed min-w-[1000px]">
            <thead>
              <tr className="bg-slate-50 text-[10px] font-black uppercase tracking-[0.2em] text-slate-500 border-b border-slate-200">
                <th className="px-6 py-5 w-[25%]">Failure Analysis Block</th>
                <th className="px-6 py-5 w-[15%]">Asset Component</th>
                <th className="px-2 py-5 w-12 text-center bg-white/30 border-l border-slate-100">S</th>
                <th className="px-2 py-5 w-12 text-center bg-white/30">O</th>
                <th className="px-2 py-5 w-12 text-center bg-white/30">D</th>
                <th className="px-4 py-5 w-20 text-center bg-white/30 border-r border-slate-100">RPN</th>
                <th className="px-6 py-5 w-[20%]">Maintenance Task</th>
                <th className="px-6 py-5 w-16 text-center">Sheet</th>
                <th className="px-6 py-5 w-20 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 bg-white">
              {methodology === 'Classical' && groupedData ? (
                Object.entries(groupedData).map(([func, failures]) => (
                  <React.Fragment key={func}>
                    <tr className="bg-slate-900 group">
                      <td colSpan={9} className="px-6 py-3">
                        <div className="flex items-center gap-3">
                           <div className="w-1.5 h-6 bg-indigo-500 rounded-full"></div>
                           <span className="text-[11px] font-black text-indigo-400 uppercase tracking-[0.25em]">Function: {func}</span>
                        </div>
                      </td>
                    </tr>
                    {Object.entries(failures).map(([fail, items]) => (
                      <React.Fragment key={fail}>
                        <tr className="bg-indigo-50/40">
                          <td colSpan={9} className="px-10 py-2.5 border-b border-indigo-100">
                            <div className="flex items-center gap-3">
                               <AlertTriangle size={12} className="text-amber-600" />
                               <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest italic">Functional Failure: {fail}</span>
                            </div>
                          </td>
                        </tr>
                        {items.map(renderRow)}
                      </React.Fragment>
                    ))}
                  </React.Fragment>
                ))
              ) : (
                processedData.map(renderRow)
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Logic Trees & Reference Overlays */}
      {selectedIntel && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200" onClick={() => setSelectedIntel(null)}>
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-2xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-200 border border-slate-100" onClick={e => e.stopPropagation()}>
             <div className="bg-slate-900 px-8 py-6 flex justify-between items-center text-white">
                <div className="flex items-center gap-4">
                   <div className="p-3 bg-indigo-500/20 rounded-xl border border-indigo-500/30"><Info size={24} className="text-indigo-200" /></div>
                   <h3 className="font-black text-xl tracking-tighter uppercase">{selectedIntel.component} <span className="text-slate-500 ml-1">Spec</span></h3>
                </div>
                <button onClick={() => setSelectedIntel(null)} className="p-2 hover:bg-white/10 rounded-full transition-all"><X size={24} /></button>
             </div>
             <div className="p-8 space-y-6 bg-slate-50/50">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative overflow-hidden">
                   <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-600"></div>
                   <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Technical Breakdown</h4>
                   <p className="text-base font-bold text-slate-800 leading-relaxed tracking-tight">{selectedIntel.componentIntel?.description}</p>
                </div>
                <div className="grid grid-cols-2 gap-6">
                   <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                      <h4 className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-2 flex items-center gap-2"><MapPin size={12} /> Asset Location</h4>
