                   </div>
                   <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                      <h4 className="text-[10px] font-black text-emerald-500 uppercase tracking-widest mb-2 flex items-center gap-2"><Eye size={12} /> Visual Indicators</h4>
                      <p className="text-sm font-black text-slate-700 uppercase">{selectedIntel.componentIntel?.visualCues}</p>
                   </div>
                </div>
