             <div className="p-6 bg-white border-t border-slate-100 flex justify-end">
                <button onClick={() => setSelectedIntel(null)} className="px-10 py-3 bg-slate-900 text-white rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-lg">Close Specification</button>
             </div>
