                                    <th className="px-8 py-4 w-40">Method</th>
                                    <th className="px-8 py-4 w-60">Criteria</th>
                                 </tr>
                              </thead>
                              <tbody className="divide-y divide-slate-100">
                                 {viewSheet.item.inspectionSheet.steps.map((step, idx) => (
                                    <tr key={idx} className="hover:bg-slate-50 transition-all">
                                       <td className="px-8 py-5 text-center font-black text-indigo-600 bg-slate-50/50">{step.step}</td>
                                       <td className="px-8 py-5 text-xs font-bold text-slate-800 uppercase tracking-tight">{step.description}</td>
                                       <td className="px-8 py-5"><span className="px-2 py-1 bg-indigo-50 text-indigo-600 rounded text-[9px] font-black uppercase tracking-tighter">{step.technique}</span></td>
                                       <td className="px-8 py-5"><div className="flex gap-2 items-center text-[10px] font-bold text-emerald-600 italic"><CheckCircle size={12}/> {step.criteria}</div></td>
                                    </tr>
                                 ))}
                              </tbody>
                           </table>
                        </div>
                     </div>
                  ) : (
                     <div className="flex flex-col items-center justify-center h-full space-y-4">
                        <div className="p-10 bg-white rounded-full shadow-2xl border border-slate-100 animate-pulse"><ClipboardList size={64} className="text-slate-200" /></div>
                        <p className="text-slate-400 font-bold uppercase tracking-widest text-[11px]">Sheet Data Not Generated</p>
                     </div>
                  )}
               </div>
               <div className="p-8 bg-white border-t border-slate-100 flex justify-end gap-4 shrink-0">
                  <button onClick={() => setViewSheet(null)} className="px-12 py-4 bg-slate-900 text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all shadow-xl active:scale-95">Close Protocol</button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
