const App: React.FC = () => {
  const [activeInputTab, setActiveInputTab] = useState<'manual' | 'upload'>('manual');
  const [methodology, setMethodology] = useState<AnalysisMethodology>('Component');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // History for Undo System
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Persistence
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Modals
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(false);

  useEffect(() => {
    const initData = async () => {
      const welcomeShown = localStorage.getItem('rcm_welcome_shown');
      if (!welcomeShown) setShowWelcome(true);
      try {
        const [studies, fetchedFolders] = await Promise.all([getAllStudies(), getAllFolders()]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        setError("Could not initialize repository.");
      }
    };
    initData();
  }, []);

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Operational context is mandatory for synthesis.");
      return;
    }
    setIsLoading(true);
    setError(null);
    try {
      const data = await generateRCMAnalysis(contextText, fileData, methodology, isMerging ? (results || []) : []);
      if (isMerging && results) {
        setResults([...results, ...data]);
      } else {
        setResults(data);
      }
    } catch (err: any) {
      setError(err.message || "Synthesis engine encountered an error.");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSaveStudy = async () => {
    if (!results && !contextText) return;

    const study: SavedStudy = {
      id: currentStudyId || `study-${Date.now()}`,
      name: studyName.trim() || "Untitled Analysis",
      timestamp: Date.now(),
      items: results || [],
      contextText,
      methodology
    };

    try {
      await saveStudyToDB(study);
      setSavedStudies(await getAllStudies());
      setCurrentStudyId(study.id);
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);
    } catch (e) {
      setError("Failed to persist analysis to database.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setMethodology(study.methodology || 'Component');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const handleNewStudy = () => {
    setResults(null);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setMethodology('Component');
    if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const handleUpdateResults = (newData: RCMItem[]) => {
    if (results) setHistory(prev => [...prev.slice(-19), results]);
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const last = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(last);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden text-slate-900">
      <WelcomeModal isOpen={showWelcome} onClose={() => { setShowWelcome(false); localStorage.setItem('rcm_welcome_shown', 'true'); }} />
      <Sidebar 
        studies={savedStudies} 
        folders={folders}
        currentStudyId={currentStudyId} 
        onSelect={handleLoadStudy} 
        onDelete={async (id) => { await deleteStudyFromDB(id); setSavedStudies(await getAllStudies()); }} 
        onNew={handleNewStudy} 
        onNewFolder={async (n) => { await saveFolderToDB({id: `f-${Date.now()}`, name: n, timestamp: Date.now()}); setFolders(await getAllFolders()); }}
        onDeleteFolder={async (id) => { await deleteFolderFromDB(id); setFolders(await getAllFolders()); }}
        onMoveStudy={() => {}} 
        onExport={() => {}} 
        onExportFolder={() => {}} 
        onImport={() => {}} 
        onToggleFinished={() => {}}
      />

      <div className="flex-1 flex flex-col min-w-0">
        <header className="h-20 bg-white border-b border-slate-200 px-8 flex items-center justify-between shrink-0">
          <div className="flex items-center gap-6 min-w-0">
            <button className="md:hidden p-2 -ml-2 text-slate-500" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
            <div className="flex flex-col min-w-0">
              <input 
                type="text" 
                value={studyName} 
                onChange={(e) => setStudyName(e.target.value)} 
                className="text-xl font-black text-slate-900 bg-transparent focus:outline-none w-full sm:w-80 truncate" 
                placeholder="Analysis Title"
              />
              <div className="flex items-center gap-2 mt-0.5">
                <span className="text-[9px] font-black uppercase tracking-widest text-indigo-500">RCM Professional Suite</span>
                <span className="w-1 h-1 rounded-full bg-slate-300"></span>
                <span className="text-[9px] font-black uppercase tracking-widest text-slate-400">SAE JA1011</span>
              </div>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <div className="hidden lg:flex items-center gap-2 pr-4 border-r border-slate-100">
              <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 font-bold text-[11px] uppercase tracking-wider transition-colors"><BookOpen size={16} /> Scoring</button>
              <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 font-bold text-[11px] uppercase tracking-wider transition-colors"><GitBranch size={16} /> Decision Tree</button>
            </div>
            <button onClick={handleSaveStudy} className={`flex items-center gap-2.5 px-6 py-2.5 rounded-2xl text-[10px] font-black uppercase tracking-[0.15em] transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white' : 'bg-slate-900 text-white hover:bg-indigo-600'}`}>
              {justSaved ? <CheckCircle2 size={16} /> : <Save size={16} />}
              {justSaved ? "Analysis Saved" : "Commit Strategy"}
            </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-8 custom-scrollbar">
          <div className="max-w-7xl mx-auto space-y-10">

            {/* Methodology & Input Workspace */}
            <div className="bg-white rounded-[2.5rem] shadow-sm border border-slate-200 overflow-hidden">
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-6 flex justify-between items-center">
                <div className="flex gap-10">
                  <button onClick={() => setActiveInputTab('manual')} className={`pb-5 text-[10px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeInputTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}><Type size={14} /> Synthesis</button>
                  <button onClick={() => setActiveInputTab('upload')} className={`pb-5 text-[10px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeInputTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400'}`}><Upload size={14} /> Knowledge</button>
                </div>

                {/* GENERAL METHODOLOGY TABS */}
                <div className="pb-5 pr-2">
                   <div className="flex bg-slate-100 p-1.5 rounded-[1.2rem] border border-slate-200/60 shadow-inner">
                      <button 
                        onClick={() => setMethodology('Component')}
                        className={`flex items-center gap-2.5 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${methodology === 'Component' ? 'bg-white text-emerald-600 shadow-xl ring-1 ring-black/5' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        <ComponentIcon size={14} /> Component-Based RCM
                      </button>
                      <button 
                        onClick={() => setMethodology('Classical')}
                        className={`flex items-center gap-2.5 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${methodology === 'Classical' ? 'bg-white text-indigo-600 shadow-xl ring-1 ring-black/5' : 'text-slate-400 hover:text-slate-600'}`}
                      >
                        <Layers size={14} /> Classical RCM
                      </button>
                   </div>
                </div>
              </div>

              <div className="p-8">
                {activeInputTab === 'manual' ? (
                  <div className="space-y-6 animate-in fade-in duration-500">
                    <div className="flex justify-between items-center">
                      <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Synthesis</label>
                      <button onClick={() => setShowContextBuilder(true)} className="flex items-center gap-2 px-5 py-2.5 bg-indigo-50 text-indigo-600 rounded-xl text-[10px] font-black uppercase tracking-widest hover:bg-indigo-100 transition-all"><Sparkles size={14} /> Launch Context Wizard</button>
                    </div>
                    <textarea 
                      value={contextText} 
                      onChange={e => setContextText(e.target.value)} 
                      className="w-full h-44 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] outline-none focus:border-indigo-500 focus:bg-white transition-all font-medium text-slate-700 shadow-inner resize-none" 
                      placeholder="Define the asset boundaries, operating environment, and performance requirements..."
                    />
                  </div>
                ) : (
                  <div className="py-12 flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-[2.5rem] bg-slate-50 hover:bg-indigo-50/20 transition-all cursor-pointer relative group">
                    <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={async (e) => {
                       const file = e.target.files?.[0];
                       if (!file) return;
                       const reader = new FileReader();
                       reader.onloadend = () => {
                         setFileData({ name: file.name, mimeType: file.type, data: (reader.result as string).split(',')[1] });
                       };
                       reader.readAsDataURL(file);
                    }} />
                    <div className="p-4 bg-white rounded-2xl shadow-xl text-indigo-600 mb-4 group-hover:scale-110 transition-transform"><FileSearch size={32} /></div>
                    <p className="text-xs font-black uppercase tracking-widest text-slate-400">Ingest Engineering Documentation</p>
                  </div>
                )}

                <div className="mt-8 flex justify-end items-center gap-4">
                  {results && results.length > 0 && (
                    <label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer">
                      <input type="checkbox" checked={isMerging} onChange={e => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded" />
                      <span className="text-[10px] font-black text-slate-600 uppercase tracking-widest">Append to Current Study</span>
