                  )}
                  <button onClick={handleGenerate} disabled={isLoading} className="flex items-center gap-3 px-12 py-4 bg-indigo-600 text-white rounded-[1.5rem] text-[11px] font-black uppercase tracking-[0.25em] shadow-2xl shadow-indigo-100 hover:bg-indigo-700 hover:-translate-y-0.5 transition-all active:scale-95 disabled:bg-slate-300">
                    {isLoading ? <Loader2 size={20} className="animate-spin" /> : <Zap size={20} />}
                    {isLoading ? "Synthesizing Strategy..." : `Initiate ${methodology} RCM`}
